static uint64_t _get_max_resolution(int ch, int stream_num)
{
	int i=0;
	uint64_t result=0;
	mtable *runtime = get_runtime();
	uint64_t shift_res_table_sort_ascending[NF_IPCAM_RES_MAX] = {
		SHIFT_64_16,
		SHIFT_64_00,
		SHIFT_64_01,
		SHIFT_64_02,
		SHIFT_64_43,
		SHIFT_64_03,
		SHIFT_64_15,
		SHIFT_64_17,
		SHIFT_64_18,
		SHIFT_64_04,


		SHIFT_64_05,
		SHIFT_64_07,
		SHIFT_64_19,
		SHIFT_64_06,
		SHIFT_64_42,
		SHIFT_64_08,
		SHIFT_64_21,
		SHIFT_64_11,
		SHIFT_64_09,
		SHIFT_64_10,


		SHIFT_64_20,
		SHIFT_64_12,
		SHIFT_64_41,
		SHIFT_64_22,
		SHIFT_64_13,
		SHIFT_64_14,
		SHIFT_64_23,
		SHIFT_64_24,
		SHIFT_64_25,
		SHIFT_64_38,


		SHIFT_64_26,
		SHIFT_64_27,
		SHIFT_64_40,
		SHIFT_64_28,
		SHIFT_64_29,
		SHIFT_64_30,
		SHIFT_64_31,
		SHIFT_64_32,
		SHIFT_64_33,
		SHIFT_64_34,


		SHIFT_64_35,
		SHIFT_64_36,
		SHIFT_64_37,
		SHIFT_64_39,
	};

	if(stream_num <= 1) // 현재 stream 2개만 지원
	{
		for(i=0; i<NF_IPCAM_RES_MAX; i++)
		{
			if(runtime[ch].encoder.res_support[stream_num] & shift_res_table_sort_ascending[i])
			{
				result = shift_res_table_sort_ascending[i];
			}
		}
	}
	return result;
}

static int _get_mp_from_res(uint64_t res)
{
	int mp=0;

	if(res==NF_IPCAM_RES_3840x2160 || res==NF_IPCAM_RES_3000x3000)
		mp = 8;
	else if(res == NF_IPCAM_RES_3072x2048 || res == NF_IPCAM_RES_3200x2400 || res == NF_IPCAM_RES_3200x1800 || res == NF_IPCAM_RES_2880x2160)
		mp = 6;
	else if(res == NF_IPCAM_RES_2592x1920 || res == NF_IPCAM_RES_2592x1944 || res == NF_IPCAM_RES_2560x1920)
		mp = 5;
	else if(res == NF_IPCAM_RES_2688x1520 || res == NF_IPCAM_RES_2048x2048 || res==NF_IPCAM_RES_2560x1600)
		mp = 4;
	else if(res == NF_IPCAM_RES_2048x1536)
		mp = 3;
	else if(res == NF_IPCAM_RES_1920x1080)
		mp = 2;
	else if(res == NF_IPCAM_RES_1280x720)
		mp = 1;
	
	return mp;
}


