// ONTHEFLY
 
typedef struct __onvif_onthefly_db
{
	char vendor[64];
	char model[64];
	char swver[64];

	int resolution;
	int fps;
	int bitrate;

	struct __onvif_onthefly_db* next;
} _onvif_onthefly_db;

static _onvif_onthefly_db _onthefly_db_head =
{
	"s",
	"AMZ-2210",
	"AS65_ALL001_V0.02.03",
	0,
	1,
	1,
	NULL
};

static GStaticMutex _onthefly_db_lock = G_STATIC_MUTEX_INIT;

static void _onthe_fly_db_lock()
{
	g_static_mutex_lock(&_onthefly_db_lock);
}

static void _onthe_fly_db_unlock()
{
	g_static_mutex_unlock(&_onthefly_db_lock);
}

/**
 * @brief Onthefly 카메라 목록에서 onthefly 여부를 조회한다.
 * @param[in] vendor 카메라 vendor.
 * @param[in] model 카메라 모델명.
 * @param[in] swver 카메라 버전.
 * @param[out] resolution 해상도 onthefly 여부.
 * @param[out] fps fps onthefly 여부.
 * @param[out] bitrate bitrate onthefly 여부.
 * @return 목록에서 조회 성공시 1, 목록에 없을 시 0.
 *
 * 현재는 카메라 vendor명만으로 체크하며, 추후 문제생길 시 model명 비교 추가하면 된다.
 */
extern int get_onvif_onthefly_db(const char* vendor, const char* model, const char* swver, int* resolution, int* fps, int* bitrate)
{
	//IPCAM_DBG(MAJOR, "vendor %s model %s swver %s\n", vendor, model, swver);
	_onthe_fly_db_lock();
	int found = 0;
	_onvif_onthefly_db* worker = &_onthefly_db_head;
	if(worker == NULL)
	{
		_onthe_fly_db_unlock();
		return found;
	}

	*resolution = *fps = *bitrate = 0;
	while(worker != NULL)
	{
		/* easy way : compare vendor only */
		if(strcmp(vendor, worker->vendor) == 0)
		{
			found = 1;
			*resolution = worker->resolution;
			*fps = worker->fps;
			*bitrate = worker->bitrate;
			break;
		}

		worker = worker->next;
	}

	//IPCAM_DBG(MAJOR, "found %d resol %d fps %d bitrate %d\n", found, *resolution, *fps, *bitrate);
	_onthe_fly_db_unlock();
	return found;
}

/**
 * @brief Onthefly 카메라 목록에 현재 카메라의 onthefly 테스트 결과를 저장한다.
 * @param[in] vendor 카메라 vendor.
 * @param[in] model 카메라 모델명.
 * @param[in] swver 카메라 버전.
 * @param[in] resolution 해상도 onthefly 여부.
 * @param[in] fps fps onthefly 여부.
 * @param[in] bitrate bitrate onthefly 여부.
 * @return 1 - 성공, 0 - 실패.
 */
extern int set_onvif_onthefly_db(const char* vendor, const char* model, const char* swver, int resolution, int fps, int bitrate)
{
	//IPCAM_DBG(MAJOR, "vendor %s model %s swver %s fps %d bitrate %d\n", vendor, model, swver, fps, bitrate);
	_onthe_fly_db_lock();
	int append = 0;
	_onvif_onthefly_db* worker = &_onthefly_db_head;
	if(worker == NULL)
	{
		_onthe_fly_db_unlock();
		return 0;
	}

	if(strcmp(vendor, worker->vendor) == 0)
	{
		append = 1;
	}
	else
	{
		while(worker->next != NULL)
		{
			worker = worker->next;
			if(strcmp(vendor, worker->vendor) == 0)
			{
				append = 1;
				break;
			}
		}
	}

	if(append)
	{
		/*  do nothing here */
	}
	else
	{
		worker->next = (_onvif_onthefly_db *)malloc(sizeof(_onvif_onthefly_db));
		if(worker->next == NULL)
		{
			IPCAM_DBG(WARN, "No Free memory!!\n");
			_onthe_fly_db_unlock();
			return 0;
		}

		worker = worker->next;
		worker->next = NULL;
	}
	strncpy(worker->vendor, vendor, 63);
	strncpy(worker->model, model, 63);
	strncpy(worker->swver, swver, 63);
	worker->resolution = resolution;
	worker->fps = fps;
	worker->bitrate= bitrate;

	_onthe_fly_db_unlock();
	return 1;
}


// Find Camera API

extern int find_this_name(char* name)
{
	int i;

	for (i=0; i<modeldb_cnt; i++)
	{
		if (strncmp(ipcam_model_db[i].name, name, strlen(ipcam_model_db[i].name)) == 0)
		{
			return (1);
		}
	}

	return (0);
}

extern int find_onvif_name(char* name)
{
	int i;

	for (i=0; i<onvif_modeldb_cnt; i++)
	{
		if (strncmp(ipcam_onvif_model_db[i].name, name, strlen(ipcam_model_db[i].name)) == 0)
		{
			return (1);
		}
	}

	return (0);
}

/**
 * @brief ITX카메라 model db를 검색하여 지원여부를 확인한다.
 * @param entry 카메라 접속정보가 담긴 struct.
 * @return 호환 카메라 일 경우 IPX_SEARCH_FOUND, 지원하지 않는 카메라일 경우IPX_SEARCH_FOUND_NOT_SUPPORTED. @see __IPX_IPCAM_RESULTS_
 */
extern int search_ipcam_model(NFOpenmodeCamInfo* entry)
{
	gint ch;
	gint i;
	gint j;

	ch = entry->ch;
	if (nf_sysman_get_fwver_vendor() == 46)
	{
		if (strcmp(entry->model, "Novus") != 0)
		{
			IPCAM_DBG(MINOR, "Blacklist IP Camera(%s, %s)\n", entry->vendor, entry->model);
			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
	}

	for (i=0; i < modeldb_cnt; i++)
	{
		if (strcmp(ipcam_model_db[i].name, entry->model) == 0)
		{
			break;
		}
	}
	for (j=0; j < modeldb_cnt; j++)
	{
		if (strcmp(ipcam_model_db[j].name, entry->model_std) == 0)
		{
			break;
		}
	}

	if (i >= modeldb_cnt && j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) model(%s,%s) unsupported\n", ch, entry->model, entry->model_std);
		return IPX_SEARCH_FOUND_NOT_SUPPORTED;
	}
	if (j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) Cam SW version incompatible\n", ch);
	}
	else
	{
		i = j;
	}

	return IPX_SEARCH_FOUND;
}

/**
 * @brief Open모드에서 ITX카메라 model db를 검색하여 runtime정보를 설정한다.
 * @param entry 카메라 접속정보가 담긴 struct.
 * @return 성공시 IPX_SEARCH_FOUND_AND_SET, 나머지는 실패. @see __IPX_IPCAM_RESULTS_
 */
extern int build_management_table_openmode(NFOpenmodeCamInfo* entry)
{
	gint ch, i, j;
	gchar ip_buf[16] = {0, };
	mtable *runtime;
	profile *found;
	int v = IPCAM_SN_VENDOR_ITX; 
	int rtn;
	int major = 0, type = 0, subtype = 0, minor = 0; // Camera SDK Version
	int view_mode=0;
	int mp=0;

	ch = entry->ch;
	if (nf_sysman_get_fwver_vendor() == 46)
	{
		if (strcmp(entry->model, "Novus") != 0)
		{
			IPCAM_DBG(MINOR, "Blacklist IP Camera(%s, %s)\n", entry->vendor, entry->model);
			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
	}

	for (i=0; i < modeldb_cnt; i++)
	{
		if (strcmp(ipcam_model_db[i].name, entry->model) == 0)
		{
			break;
		}
	}
	for (j=0; j < modeldb_cnt; j++)
	{
		if (strcmp(ipcam_model_db[j].name, entry->model_std) == 0)
		{
			break;
		}
	}

	runtime = get_runtime();
	if (runtime == NULL) { return IPX_SEARCH_FOUND_NOT_SUPPORTED; }

	if (i >= modeldb_cnt && j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) model(%s,%s) unsupported\n", ch, entry->model, entry->model_std);
		sscanf(entry->sdkver, "%d.%d.%d.%d", &major, &type, &subtype, &minor);

		basic_setup_unsupported_camera_openmode(ch, entry);
		rtn = nf_ipcam_get_json_capabilities(ch);
		if(rtn != 0)
		{
			printf("CH(%d) model(%s,%s) is not supprted camera capabilities api...\n", ch, entry->model, entry->model_std);
			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
		else
			goto default_settings;  
	}

	if (j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) Cam SW version incompatible\n", ch);
	}
	else
	{
		i = j;
	}

	found = (profile*) &ipcam_model_db[i];

	runtime[ch].func = found->func;
	runtime[ch].profile_id = i;

	runtime[ch].sys.use_ssl = entry->use_ssl;
	runtime[ch].sys.http_port = entry->http_port;
	runtime[ch].sys.rtsp_port[0] = entry->rtsp_port;
	runtime[ch].sys.rtsp_port[1] = entry->rtsp_port;
	runtime[ch].sys.rtsp_port[2] = 0;

	runtime[ch].sys.model_code = found->model_code;

	memcpy(runtime[ch].sys.macaddr, entry->macaddr, 6);
	runtime[ch].sys.ipaddr = htonl(entry->ipaddr);
	runtime[ch].sys.rx_method = NF_IPCAM_RX_METHOD_RTSP_TCP;
	strncpy(runtime[ch].sys.model,  entry->model, 64);
	strncpy(runtime[ch].sys.stdver, entry->model_std, 64);
	strncpy(runtime[ch].sys.swver,  entry->firmware_version, 64);
	strncpy(runtime[ch].sys.swver2, entry->firmware_version2, 64);
	strncpy(runtime[ch].sys.vendor, entry->vendor, 64);
	strncpy(runtime[ch].sys.sdkver, entry->sdkver, 64);
	
	/*	NPT2 - updated zoom module ver. */
	if(entry->zoom_module_name != NULL)
		strncpy(runtime[ch].sys.zoom_module_name, entry->zoom_module_name, 63);
	if(entry->zoom_module_fwver != NULL)
		strncpy(runtime[ch].sys.zoom_module_fwver, entry->zoom_module_fwver, 63);

	strncpy(runtime[ch].username, entry->u_done, 64);
	strncpy(runtime[ch].password, entry->p_done, 64);

	memcpy(&runtime[ch].video,	   &model_video_profiles[found->video],  sizeof(video_t));
	memcpy(&runtime[ch].encoder,   &model_encoder_profiles[found->encoder],sizeof(encoder_t));
	memcpy(&runtime[ch].audio,	   &model_audio_profiles[found->audio],  sizeof(audio_t));
	memcpy(&runtime[ch].image,	   &model_image_profiles[found->image],  sizeof(image_t));
	memcpy(&runtime[ch].ptz,	   &model_ptz_profiles[found->ptz],      sizeof(ptz_t));
	memcpy(&runtime[ch].alarm,	   &model_alarm_profiles[found->alarm],  sizeof(alarm_t));
	memcpy(&runtime[ch].motion,	   &model_motion_profiles[found->motion],sizeof(motion_t));
	memcpy(&runtime[ch].focus,	   &model_focus_profiles[found->focus],sizeof(focus_t));

	if( runtime[ch].focus.supported	!= 0 )
	{		
		focus_comp_info fcinfo;
		memset(&fcinfo, 0x00, sizeof(fcinfo));
		if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
		{
			runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
			runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
			runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
			runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
			runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
		}

	}

	sscanf(entry->sdkver, "%d.%d.%d.%d", &major, &type, &subtype, &minor);

	// image profile change : MaxShutter Speed max value = 5000 
	if(type == ITX_CAM_SDK_TYPE_HS && minor >= 1)
	{
		switch(found->image)
		{
			case 12 : memcpy(&runtime[ch].image, &model_image_profiles[31], sizeof(image_t)); break;
			case 13 : memcpy(&runtime[ch].image, &model_image_profiles[32], sizeof(image_t)); break;
			case 16 : memcpy(&runtime[ch].image, &model_image_profiles[33], sizeof(image_t)); break;
			case 17 : memcpy(&runtime[ch].image, &model_image_profiles[34], sizeof(image_t)); break;
			case 19 : memcpy(&runtime[ch].image, &model_image_profiles[35], sizeof(image_t)); break;
			case 20 : memcpy(&runtime[ch].image, &model_image_profiles[36], sizeof(image_t)); break;
			case 21 : memcpy(&runtime[ch].image, &model_image_profiles[37], sizeof(image_t)); break;
		}
	}

	get_ipstr(runtime[ch].sys.ipaddr, ip_buf);
	for (i = 0; i < runtime[ch].video.stream_cnt; i++)
	{
		snprintf(runtime[ch].sys.rtsp_url[i], 256, model_rtsp_addrs[found->rtsp[i]], ip_buf);
	}

	memcpy(&runtime[ch].funcs, &model_funcs[found->funcs], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
	runtime[ch].recv_handler = model_recv_handlers[found->recv_handler];

default_settings:;
	if(ip_buf[0] == 0){
		get_ipstr(runtime[ch].sys.ipaddr, ip_buf);
	}

	//CBC H265 codec remove exception code
	if(nf_ipcam_is_vendor("CBC"))
	{
		for (i = 0; i < runtime[ch].video.stream_cnt; i++){
			if(runtime[ch].encoder.vcodec[i] & NF_IPCAM_VCODEC_H264){
				runtime[ch].video.vcodec[i] = NF_IPCAM_VCODEC_H264;	
			}
		}

		/*
		runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H264;	
		runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H264;

		runtime[ch].encoder.vcodec[0] &= ~(NF_IPCAM_VCODEC_H265);
		runtime[ch].encoder.vcodec[1] &= ~(NF_IPCAM_VCODEC_H265);
		*/
	}

	if(strstr(runtime[ch].sys.stdver, "CFE")){
		view_mode = cam_get_view_mode(ch);
        if(cam_get_encode_mode(ch) > 0 || view_mode == 0){
            // cam_set_encode_mode(ch, 0);
	    // (SWIPXXP-433)
			if(view_mode == -3 ) // Not support view_mode
			{
				cam_set_fisheye_init_legacy(ch,0); //legacy fisheye config
			}
			else
			{
			    cam_set_fisheye_init(ch, 0, 1); // default setting enc_mode = 0('fisheye'), view_mode = 1('Multi')
			}
            return IPX_SEARCH_CONNECTION_FAILED;
        }
    }

	/* FIXME. Temporary exception */
	if ((strncmp(runtime[ch].sys.vendor, "GANZ", 4) == 0 && strncmp(runtime[ch].sys.model, "ZN", 2) == 0)
	 || (strncmp(runtime[ch].sys.vendor, "UTT", 3) == 0 && strncmp(runtime[ch].sys.model, "UT", 2) == 0))
	{
		snprintf(runtime[ch].sys.rtsp_url[0], 256, model_rtsp_addrs[3], ip_buf);
		snprintf(runtime[ch].sys.rtsp_url[1], 256, model_rtsp_addrs[4], ip_buf);
		v = IPCAM_SN_VENDOR_CBC;
	}

	/* ITX Camera SN Get */
	struct sn_info info;
	memset(&info, 0x00, sizeof(struct sn_info));
	if(cam_sn_get(&info, ch, v) == 0)
	{
		printf("SN INFO CH(%d): >> %s/%s/%s/%s/%s/%s/%s/%s/%s\n", ch,
				info.vendor,
				info.nation,
				info.date,
				info.mega,
				info.lens,
				info.heater,
				info.irled,
				info.sensor,
				info.ads);

		// Adaptive IR || colorvu(include anti-exposure mode)
		if(info.irled[0] == 'A' || info.irled[0] == 'W')
		{
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
			runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
		    if(type == ITX_CAM_SDK_TYPE_HS) //HISILICON 
			{
				runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF;

				if(nf_ipcam_is_vendor_videcon())
					runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}
			else
			{
				runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}

		}

		// Adjust DNN’s Sensitivity
		if(info.ads[0] == 'D')
		{
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
			runtime[ch].image.dnn_sense_ntod.min = 3;
			runtime[ch].image.dnn_sense_ntod.max = 10;
			runtime[ch].image.dnn_sense_ntod.value = 7;
			runtime[ch].image.dnn_sense_ntod.diff = 3;
			runtime[ch].image.dnn_sense_ntod.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_DTON;

			runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_DTON;
			runtime[ch].image.dnn_sense_dton.min = 0;
			runtime[ch].image.dnn_sense_dton.max = 7;
			runtime[ch].image.dnn_sense_dton.value = 4;
			runtime[ch].image.dnn_sense_dton.diff = -3;
			runtime[ch].image.dnn_sense_dton.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_NTOD;

			runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_D2N] = (gpointer)&cam_set_dnn_adjust_d2n;
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_N2D] = (gpointer)&cam_set_dnn_adjust_n2d;
		}
		if(strstr(info.vendor, "CBC") != NULL)
		{
			if(strcmp(runtime[ch].sys.stdver, "INDi-2005PR") == 0 ||
				strcmp(runtime[ch].sys.stdver,"IND-2005PR") == 0 ||
				strcmp(runtime[ch].sys.stdver,"INB-2005PR") == 0)
			{
				runtime[ch].image.exposure.value = NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION_INX;
				runtime[ch].image.wd.value = NF_IPCAM_WDR_MODE_ITX_LOW; 
				runtime[ch].image.brightness.value = 20;
				runtime[ch].image.color.value = 13;
			}
		}

		if(info.sensor[0] == '9' && type == ITX_CAM_SDK_TYPE_HS && minor > 5)//IMX291 && HS && SDK ver
		{
			if(strncmp(runtime[ch].sys.stdver, "IND", 3) == 0 
					|| strncmp(runtime[ch].sys.stdver, "INB", 3) == 0)	//INxH 2M
			{
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNR_AUTO_SMART;
				runtime[ch].image.dnr_ctr.support |= NF_IPCAM_DNR_MODE_AUTO_SMART;
			}
		}
	}

	if(runtime[ch].image.supported & NF_IPCAM_IMAGE_DNN)
	{
		runtime[ch].image.day_night.support |= NF_IPCAM_IMAGE_DN_SCHEDULE;
	}

	if(major < 6)
	{
		if (strncmp(runtime[ch].sys.stdver, "NPT", 3) == 0)
		{
			if(strcmp(entry->sdkver, "1.0.0.4") >= 0)
			{
				// FIXME. by model codes
				//runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				//memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[2], sizeof(pmask_t));
				//runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&npt_set_pmask;
				
				//add motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));
			}
			else
			{
				runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_WDR);
				memset(&runtime[ch].image.wd, 0x00, sizeof(modes));
				memset(&runtime[ch].image.focus_mode, 0x00, sizeof(modes));
			}
		}
		else if(type == ITX_CAM_SDK_TYPE_HS)
		{
			if(runtime[ch].func & NF_IPCAM_FUNC_PRIVACY_MASK)
				{
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[3], sizeof(pmask_t));
				}			

			if(minor >= 6)
			{
				if (strncmp(runtime[ch].sys.swver, "38100", 5) == 0) //3516C
				{
					//registration ROI Function
					runtime[ch].func |= NF_IPCAM_FUNC_ROI;
					memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[2], sizeof(roi_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_ROI] = (gpointer)&cam_set_roi_area;

					//DEFOG
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;

					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_LOW;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_MID;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_HIGH;
					runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_HI_OFF;
				}
				if (strncmp(runtime[ch].sys.swver, "40300", 5) == 0 || strncmp(runtime[ch].sys.swver, "48100", 5) == 0 //ITX 3516A/D
						||  strncmp(runtime[ch].sys.swver, "66000", 5) == 0) //ICA 3516D
				{
					//registration ROI Function
					runtime[ch].func |= NF_IPCAM_FUNC_ROI;

					if (strncmp(runtime[ch].sys.swver, "40300", 5) == 0)
						memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[1], sizeof(roi_t));
					else
						memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[3], sizeof(roi_t));

					runtime[ch].funcs[NF_IPCAM_TYPE_SET_ROI] = (gpointer)&cam_set_roi_area;

					// VBR+
					runtime[ch].encoder.bitctrl[0] |= NF_IPCAM_BITRATE_CONTROL_VBR_PLUS;
					if(strncmp(runtime[ch].sys.swver, "66000", 5) == 0)
					{  
						// VA FUNCTION
						runtime[ch].func |= NF_IPCAM_FUNC_VA;
						runtime[ch].funcs[NF_IPCAM_TYPE_SET_RESET_VA] = (gpointer)&cam_set_reset_va;
						runtime[ch].funcs[NF_IPCAM_TYPE_SET_VA_CONFIG] = (gpointer)&cam_set_va_config;
					}
				}
			}
			
			if(minor > 6)	
			{
				//registration External mode 
				if(strstr(runtime[ch].sys.stdver, "INX-5007P") != NULL || 
						strstr(runtime[ch].sys.stdver, "NCX-2003P") != NULL) 
				{
					runtime[ch].image.day_night.support |= 	NF_IPCAM_IRCUT_MODE_ITX_EXTERNAL;
				}
			}
		}
		else
		{
			if(strncmp(runtime[ch].sys.stdver, "IN", 2) == 0)
			{
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));

				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 3;
				runtime[ch].image.dnn_sense_ntod.max = 10;
				runtime[ch].image.dnn_sense_ntod.value = 7;
				runtime[ch].image.dnn_sense_ntod.diff = 3;
				runtime[ch].image.dnn_sense_ntod.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_DTON;

				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_DTON;
				runtime[ch].image.dnn_sense_dton.min = 0;
				runtime[ch].image.dnn_sense_dton.max = 7;
				runtime[ch].image.dnn_sense_dton.value = 4;
				runtime[ch].image.dnn_sense_dton.diff = -3;
				runtime[ch].image.dnn_sense_dton.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_NTOD;

				runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_D2N] = (gpointer)&cam_set_dnn_adjust_d2n;
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_N2D] = (gpointer)&cam_set_dnn_adjust_n2d;

				//runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
				//runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
				//runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;

				if(strstr(runtime[ch].sys.stdver, "-3005PR") != NULL)
				{
					if (strcmp(entry->sdkver, "1.0.0.6") >= 0)
					{
						runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX);
						runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_MID);
					}
				}
			}
			else
			{
				if (strcmp(entry->sdkver, "1.0.0.3") >= 0)
				{
					// FIXME. by model codes
					runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;
				}

				if (strcmp(entry->sdkver, "1.0.0.4") >= 0)
				{
					runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.slow_shutter.support |= (NF_IPCAM_IMAGE_SLSH_MODE_X4 | NF_IPCAM_IMAGE_SLSH_MODE_X8);
				}
				else
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.onthefly &= ~(NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					memset(&runtime[ch].image.anti_flicker, 0x00, sizeof(modes));
					memset(&runtime[ch].image.max_shutter, 0x00, sizeof(modes));
				}
				if (strcmp(entry->sdkver, "3.0.0.4") >= 0)
				{
					runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
					runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
					runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
						NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
						NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
					runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);

					runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
					runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);
				}

				if(strncmp(runtime[ch].sys.stdver,"NMD", 3) == 0 || strncmp(runtime[ch].sys.stdver,"NMX", 3) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH);
					if(strncmp(runtime[ch].sys.stdver,"NMDi", 4) == 0)
					{
						runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
					}
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
				}

				if(strncmp(runtime[ch].sys.stdver,"NMB", 3) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
				}

			}
		}

		//vendor for CBC (MAX AGC ISSUE)
		if(strstr(info.vendor, "CBC") != NULL)
		{
			if(major >=  5 && minor >= 8)
			{
				//set max_agc
				memset(&runtime[ch].image.max_agc, 0x00, sizeof(modes));

				runtime[ch].image.max_agc.support = 
				(NF_IPCAM_IMAGE_MAGC_MODE_CBC_0 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_1 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_2 |	NF_IPCAM_IMAGE_MAGC_MODE_CBC_3 |
			     NF_IPCAM_IMAGE_MAGC_MODE_CBC_4 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_5 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_6 |	NF_IPCAM_IMAGE_MAGC_MODE_CBC_7 |
				 NF_IPCAM_IMAGE_MAGC_MODE_CBC_8 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_9);
					
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_CBC_4);
			}
		}
	}
	else
	{
		if (type == ITX_CAM_SDK_TYPE_NPT2)
		{
			if(subtype == 0) // NPT2 x30 EH Model
			{
				// Night to Day Sensitivity
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 0;
				runtime[ch].image.dnn_sense_ntod.max = 25;
				runtime[ch].image.dnn_sense_ntod.value = 20;

				// IR Correction
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_IR_CORRECTION;
				runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_ON;
				runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_OFF;
				runtime[ch].image.ir_correction.value = NF_IPCAM_IMAGE_IR_CORRECTION_OFF;

				// Focus Near Limit
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_FOCUS_LIMIT;
				runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_30;
				runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_100;
				runtime[ch].image.focus_limit.value = NF_IPCAM_IMAGE_FOCUS_LIMIT_100;

				// Stabilizer
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
				runtime[ch].image.stabilizer.value = NF_IPCAM_IMAGE_STABILIZER_OFF;

				// Auto White Balance
				runtime[ch].image.wb.support |= NF_IPCAM_WB_MODE_ITX_AUTO_W;
				runtime[ch].image.wb.value = NF_IPCAM_WB_MODE_ITX_AUTO_W;
			}
			if(subtype == 1) // NPT2 x10, x20/x30 EV Model, 
			{
				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_COLOR);
					runtime[ch].image.exposure.support = (NF_IPCAM_IMAGE_EXP_MODE_AUTO_NPT_X10 | NF_IPCAM_IMAGE_EXP_MODE_MANUAL_NPT_X10);
					runtime[ch].image.exposure.value = NF_IPCAM_IMAGE_EXP_MODE_AUTO_NPT_X10;

					runtime[ch].image.agc.max = 18;
					runtime[ch].image.eshutter_speed.max = 60000;

					if(strstr(runtime[ch].sys.zoom_module_name, "MC-108") != NULL)
					//|| (atoi(runtime[ch].sys.zoom_module_fwver) >= 13 ) /* fwver check */
					{
						runtime[ch].image.eshutter_speed.max = 30000;
					}

					runtime[ch].image.sharpness.max = 10;
				}

				//Motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));

				//runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				//runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&npt_set_pmask;
				//memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));

				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_LOW;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_MID;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HIGH;

				if(strstr(runtime[ch].sys.stdver, "-2003P30-EV") != NULL)
				{
					runtime[ch].image.defog.support = NF_IPCAM_IMAGE_DEFOG_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_ON;

					runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
					runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
					runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
					runtime[ch].image.stabilizer.value = NF_IPCAM_IMAGE_STABILIZER_OFF;
				}

				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_MAXAGC);

					runtime[ch].image.defog.support = NF_IPCAM_IMAGE_DEFOG_X10_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_LOW;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_MID;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_HIGH;
				}

				// HLC
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_HLC;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_OFF;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_LOW;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_MID;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_HIGH;

				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.hlc.support = NF_IPCAM_HLC_X10_OFF;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_LOW;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_MID;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_HIGH;
				}

				// Night to Day Sensitivity
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 0;
				runtime[ch].image.dnn_sense_ntod.max = 25;
				runtime[ch].image.dnn_sense_ntod.value = 20;

				// WDR
				runtime[ch].image.wd.support = NF_IPCAM_WDR_MODE_ITX_OFF |
					NF_IPCAM_WDR_MODE_ITX_NPT_LOW |
					NF_IPCAM_WDR_MODE_ITX_NPT_MID |
					NF_IPCAM_WDR_MODE_ITX_NPT_HIGH;
				runtime[ch].image.wd.value = NF_IPCAM_WDR_MODE_ITX_OFF;

				if(strstr(runtime[ch].sys.stdver, "-2003P20-EV") != NULL ||
					strstr(runtime[ch].sys.stdver, "-2003P30-EV") != NULL)
				{
					// IR Correction
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_IR_CORRECTION;
					runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_ON;
					runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_OFF;
					runtime[ch].image.ir_correction.value = NF_IPCAM_IMAGE_IR_CORRECTION_OFF;

					// Focus Near Limit
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_FOCUS_LIMIT;
					runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_30;
					runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_100;
					runtime[ch].image.focus_limit.value = NF_IPCAM_IMAGE_FOCUS_LIMIT_100;

					// Auto White Balance
					runtime[ch].image.wb.support |= NF_IPCAM_WB_MODE_ITX_AUTO_W;
					runtime[ch].image.wb.value = NF_IPCAM_WB_MODE_ITX_AUTO_W;
				}
			}

			// IR Cut Filter
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_IRCUTM;

			// Anti-Flicker
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_ANTIFLICKER;

			if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
			{
				runtime[ch].image.anti_flicker.support = NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_ON;
				runtime[ch].image.anti_flicker.support |= NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_OFF;
				runtime[ch].image.anti_flicker.value = NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_OFF;
				
				//Motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[11],sizeof(motion_t));
			}
				
		}
		if (type == ITX_CAM_SDK_TYPE_IRPTZ)
		{
			if(strstr(runtime[ch].sys.stdver, "-2003R20") != NULL)
			{
				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_LOW;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_MID;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HIGH;
				runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_OFF;

			}
			if(strstr(runtime[ch].sys.stdver, "-2003R30") != NULL)
			{
				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_ON;
				runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_OFF;

				// Stabilizer
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
				runtime[ch].image.stabilizer.value |= NF_IPCAM_IMAGE_STABILIZER_OFF;
			}
		}
		
		if(type == ITX_CAM_SDK_TYPE_TI368 || type == ITX_CAM_SDK_TYPE_TI385 || type == ITX_CAM_SDK_TYPE_DMVAI)
		{
			if(type == ITX_CAM_SDK_TYPE_TI385)
			{
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));

				if(strstr(runtime[ch].sys.stdver, "-3005PR") != NULL)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX);
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_MID);
				}

				//runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
				//runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
				//runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}


			if(type == ITX_CAM_SDK_TYPE_TI368)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;

				runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.slow_shutter.support |= (NF_IPCAM_IMAGE_SLSH_MODE_X4 | NF_IPCAM_IMAGE_SLSH_MODE_X8);

				runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
				runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
				runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
					NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
					NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
				runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);

				runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
				runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);

				if(strncmp(info.lens, "PT", 2) == 0 || 	strncmp(info.lens, "P2", 2) == 0 || strncmp(info.lens, "ZZ", 2) == 0 || strncmp(info.lens, "P3", 2) == 0)
				{
					runtime[ch].focus.dnn_comp.value = 1;

					if(strncmp(info.vendor, "KON", 3) == 0 || strncmp(info.lens, "P3", 2) == 0)
						runtime[ch].focus.dnn_comp.value = 0;

					runtime[ch].focus.supported |= NF_IPCAM_FOCUS_DNN_COMP;
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_FOCUS_COMP] = cam_set_focus_comp;
					focus_comp_info fcinfo;
					memset(&fcinfo, 0x00, sizeof(fcinfo));
					if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
					{
						runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
						runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
						runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
						runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
						runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
					}

					if(nf_sysman_get_fwver_vendor() == 65 || nf_sysman_get_fwver_vendor() == 98) // Takenaka
						runtime[ch].focus.dnn_comp.value = 0;
				}

				if(strncmp(runtime[ch].sys.stdver, "NMX", 3) == 0)
				{
					focus_comp_info fcinfo;
					memset(&fcinfo, 0x00, sizeof(fcinfo));
					if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
					{
						runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
						runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
						runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
						runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
						runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
					}

					runtime[ch].focus.supported |= NF_IPCAM_FOCUS_TEM_COMP;
					if(strncmp(info.vendor, "KMW", 3) == 0)
						runtime[ch].focus.tem_comp.value = 0;
					else
						runtime[ch].focus.tem_comp.value = 1;

					runtime[ch].focus.dnn_comp.value = 0;
					runtime[ch].focus.supported &= ~(NF_IPCAM_FOCUS_DNN_COMP);
					if(strncmp(info.irled, "C", 1) == 0)
					{
						runtime[ch].focus.dnn_comp.value = 1;
						runtime[ch].focus.supported |= NF_IPCAM_FOCUS_DNN_COMP;
					}

					if(nf_sysman_get_fwver_vendor() == 65 || nf_sysman_get_fwver_vendor() == 98) // Takenaka
					{
						runtime[ch].focus.dnn_comp.value = 0;
						runtime[ch].focus.tem_comp.value = 0;
					}

					runtime[ch].funcs[NF_IPCAM_TYPE_SET_FOCUS_COMP] = cam_set_focus_comp;
				}

			}
			if (type == ITX_CAM_SDK_TYPE_DMVAI)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;

				runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
				runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);

				runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
				runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
				runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
					NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
					NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
				runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);
			}

			if(strncmp(runtime[ch].sys.stdver,"NMD", 3) == 0 || strncmp(runtime[ch].sys.stdver,"NMX", 3) == 0)
			{
				runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH);
				if(strncmp(runtime[ch].sys.stdver,"NMDi", 4) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
				}
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
			}

			if(strncmp(runtime[ch].sys.stdver,"NMB", 3) == 0)
			{
				runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
			}
		}
	}

/*
	if(!nf_ipcam_is_vendor("CBC")) {
		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}
	
		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_VBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_VBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;	
		}
	}
	*/

	//min bitrate modify
	//runtime[ch].encoder.min_bitrate[0] = 1000;
	//runtime[ch].encoder.min_bitrate[1] = 600;

	if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
	{
		/*
		if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
		{
			runtime[ch].encoder.max_bitrate[0] = 4000;
		}
		if(runtime[ch].encoder.max_bitrate[1] > 1000 || runtime[ch].encoder.max_bitrate[1] <= 0)
		{		
			runtime[ch].encoder.max_bitrate[1] = 1000;
		}
		*/

		//IPXUHD-1660
		runtime[ch].encoder.max_bitrate[0] = 8000;
		runtime[ch].encoder.max_bitrate[1] = 2000;
		runtime[ch].encoder.min_bitrate[0] = 1000;
		runtime[ch].encoder.min_bitrate[1] = 600;

		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
		}
	}

#if defined(_IPX_32P4E)  || defined(_IPX_32M4E) || defined(_IPX_32P5)
	runtime[ch].encoder.max_bitrate[0] = 4000;
	runtime[ch].encoder.max_bitrate[1] = 1000;

	runtime[ch].encoder.min_bitrate[0] = 1500;
	runtime[ch].encoder.min_bitrate[1] = 600;

	if(runtime[ch].encoder.bitctrl[0] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;
	if(runtime[ch].encoder.bitctrl[1] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;
#endif

	if(runtime[ch].image.supported & NF_IPCAM_IMAGE_COLORVU){
		runtime[ch].image.colorvu_level.min = 1;
		runtime[ch].image.colorvu_level.max = 200;
		runtime[ch].image.colorvu_level.value = 200;
		runtime[ch].image.colorvu_ctrl.value = NF_IPCAM_COLORVU_CTRL_AUTO;
	}

	//ipcam ntp timesync setting 
	if(runtime[ch].funcs[NF_IPCAM_TYPE_INIT] == NULL)
		runtime[ch].funcs[NF_IPCAM_TYPE_INIT] = (gpointer)&cam_set_time_info;

	if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
	{
		/*
		if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
		{
			runtime[ch].encoder.max_bitrate[0] = 4000;
		}
		if(runtime[ch].encoder.max_bitrate[1] > 1000 || runtime[ch].encoder.max_bitrate[1] <= 0)
		{		
			runtime[ch].encoder.max_bitrate[1] = 1000;
		}
		*/

		//IPXUHD-1660
		//runtime[ch].encoder.max_bitrate[0] = 8000;
		//runtime[ch].encoder.max_bitrate[1] = 2000;
		runtime[ch].encoder.max_bitrate[0] = 4000;
		runtime[ch].encoder.max_bitrate[1] = 1000;
		runtime[ch].encoder.min_bitrate[0] = 1000;
		runtime[ch].encoder.min_bitrate[1] = 600;

		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
		}
	}

	if(nf_ipcam_is_vendor_zicom())
	{
		// resolution setting
		runtime[ch].video.resolution.resolution[0] = _get_max_resolution(ch, 0);

		// bitrate setting
		mp = _get_mp_from_res(runtime[ch].video.resolution.resolution[0]);
		if(mp == 8)
		{
			runtime[ch].video.bitrate[0].value = 4000;
		}
		else if(mp == 5)
		{
			runtime[ch].video.bitrate[0].value = 4000;
		}
		else if(mp == 2)
		{
			runtime[ch].video.bitrate[0].value = 2000;
		}
		else
		{
			runtime[ch].video.bitrate[0].value = runtime[ch].encoder.max_bitrate[0] >= 4000 ? 4000 : runtime[ch].encoder.max_bitrate[0]; // itx basic set 
		}


		// codec setting
		runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H264;
		runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H264;

		/*
		// smart motion setting
		if(runtime[ch].motion.smart_motion_support)
		{
			runtime[ch].motion.smart_motion_enable = 1;
			for(i=0; i<runtime[ch].motion.smart_motion_option_size; i++)
			{
				runtime[ch].motion.smart_motion_options[i].threshold = 50;
			}
			runtime[ch].motion.sensitivity.value = 5;
		}
		*/

	}

	_modify_2nd_stream_supported_res(ch);

    nf_api_ai_config_update(ch);


	return IPX_SEARCH_FOUND_AND_SET;
}

/**
 * @brief Open모드에서 ONVIF카메라 model db를 검색하여 runtime정보를 설정한다.
 * @param entry 카메라 접속정보가 담긴 struct.
 * @return 성공시 IPX_SEARCH_FOUND_AND_SET, 나머지는 실패. @see __IPX_IPCAM_RESULTS_
 */
extern int build_management_table_openmode_onvif(NFOpenmodeCamInfo* entry)
{
	int i;
	int result = 0;
	int ch;
	int temp_rtn;
	int auth_cnt = 0;
	mtable *runtime = NULL;
	profile *found = NULL;
	char ip_buf[16];
	ch = entry->ch;

	IPCAM_DBG(MAJOR, "start CH(%d)\n", ch);
	IPCAM_DBG(MINOR, "Model db has [%d] entries\n", onvif_modeldb_cnt);

	runtime = get_runtime();

	strncpy(runtime[ch].username, entry->u_done, 64);
	strncpy(runtime[ch].password, entry->p_done, 64);
	memcpy(runtime[ch].sys.macaddr, entry->macaddr, 6);
	runtime[ch].sys.model_code = NF_IPCAM_MODEL_ONVIF;
	runtime[ch].sys.ipaddr = htonl(entry->ipaddr);
	runtime[ch].sys.http_port = entry->http_port;
	runtime[ch].sys.rx_method = NF_IPCAM_RX_METHOD_RTSP_TCP;
	strncpy(runtime[ch].sys.model,  entry->model, 64);
	strncpy(runtime[ch].sys.stdver, entry->model_std, 64);
	strncpy(runtime[ch].sys.swver,  entry->firmware_version, 64);
	strncpy(runtime[ch].sys.swver2, entry->firmware_version2, 64);
	strncpy(runtime[ch].sys.vendor, entry->vendor, 64);
	strncpy(runtime[ch].sys.sdkver, entry->sdkver, 64);
/////////////////////////////
#if 0
	/* onthefly query added */
	{
		int resol, fps, bitrate;
		int rtn = get_onvif_onthefly_db(runtime[ch].sys.vendor,
				runtime[ch].sys.model,
				runtime[ch].sys.swver, &resol, &fps, &bitrate);

		if(rtn == 0)
		{
			runtime[ch].onvif.query_onthefly_state = 1;
		}
		else
		{
			if(fps)
			{
				runtime[ch].video.supported |= VIDEO_SETUP_FPS;
				runtime[ch].video.onthefly |= VIDEO_SETUP_FPS;
			}
			if(bitrate)
			{
				runtime[ch].video.supported |= VIDEO_SETUP_BITRATE;
				runtime[ch].video.onthefly |= VIDEO_SETUP_BITRATE;
			}
		}
	}
#endif
	for (i = 0; i < onvif_modeldb_cnt; i++)
	{
		if (strncmp(ipcam_onvif_model_db[i].name, runtime[ch].sys.model, strlen(ipcam_onvif_model_db[i].name)) == 0)
		{
			break;
		}
	}

	if (i >= onvif_modeldb_cnt)
	{
		if (strcmp(runtime[ch].sys.vendor, "MESSOA") == 0)
		{
			i = get_the_model_id("ANNEXXUS");
		}
		else if(strcmp(runtime[ch].sys.vendor, "Grundig") == 0 || strcmp(runtime[ch].sys.vendor, "GRUNDIG") == 0)
		{
			memcpy(&runtime[ch].funcs, &model_funcs[10], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
			//runtime[ch].funcs[NF_IPCAM_TYPE_SET_ACODEC] = &grundig_set_audio;
			//runtime[ch].sys.model_code = NF_IPCAM_MODEL_ONVIF_GRUNDIG;
			memcpy(&runtime[ch].motion, &model_motion_profiles[3], sizeof(motion_t));
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &grundig_set_motion_area;
			runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
			runtime[ch].recv_handler = model_recv_handlers[3];
		}
		else if(strcmp(runtime[ch].sys.vendor, "AXIS") == 0)
		{
			IPCAM_DBG(MINOR, "CH(%d) AXIS\n", ch);
			memcpy(&runtime[ch].motion, &model_motion_profiles[7], sizeof(motion_t));
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &nf_axis_set_motion;
			runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_IMAGE_ONVIF] = &nf_axis_set_image;
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_MIRROR] = &nf_axis_set_mirror;	
		}
		else if(strcmp(runtime[ch].sys.vendor, "H264") == 0)
		{
			IPCAM_DBG(MINOR, "CH(%d) Xiongmai\n", ch);
			memcpy(&runtime[ch].motion, &model_motion_profiles[10], sizeof(motion_t));
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &xiongmai_motion_set;
			runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
			runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM0] = &xiongmai_alarm_server_set;
			runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM1] = &xiongmai_osd_off;
			runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM2] = &xiongmai_prevent_periodical_reboot;
			runtime[ch].func |= NF_IPCAM_FUNC_AUDIO_TX;
		}
		else
		{
			IPCAM_DBG(MINOR, "CH(%d) model db not found\n", ch);
		}

		if(nf_ipcam_is_vendor_orion() || nf_ipcam_is_vendor_g4s())
		{
			if(strcasecmp(runtime[ch].sys.vendor, "Orion") == 0 || strcasecmp(runtime[ch].sys.vendor, "G4S") == 0)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[4], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&huviron_set_privacy_mask;
			}
			else if(strcasecmp(runtime[ch].sys.vendor, "HDPRO") == 0)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[5], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&nf_hdpro_set_privacy_mask;
			}
		}
	}
	if(i < onvif_modeldb_cnt)
	{
		found = (profile*) &ipcam_onvif_model_db[i];

		runtime[ch].func = found->func;

		memcpy(&runtime[ch].video, &model_video_profiles[found->video],  sizeof(video_t));
		memcpy(&runtime[ch].audio, &model_audio_profiles[found->audio],  sizeof(audio_t));
		//memcpy(&runtime[ch].image, &model_image_profiles[found->image],  sizeof(image_t));
		//memcpy(&runtime[ch].ptz,   &model_ptz_profiles[found->ptz],      sizeof(ptz_t));
		memcpy(&runtime[ch].alarm, &model_alarm_profiles[found->alarm],  sizeof(alarm_t));
		memcpy(&runtime[ch].motion,&model_motion_profiles[found->motion],sizeof(motion_t));
		memcpy(&runtime[ch].funcs, &model_funcs[found->funcs], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
		runtime[ch].recv_handler = model_recv_handlers[found->recv_handler];
	}

	strncpy(runtime[ch].onvif.xaddr_dev_tail, "onvif/device_service", 128);
	runtime[ch].onvif.auth_method = entry->auth;

// FIXME temp exception handling for CP 4.3 huviron cam connection
	if (strcmp(runtime[ch].sys.vendor, "iplinker") == 0)
	{
		strncpy(runtime[ch].username, "admin", 64);
		strncpy(runtime[ch].password, "admin", 64);
	}
	else if (strncasecmp(runtime[ch].sys.vendor, "Orion", 64) == 0)
	{
		strncpy(runtime[ch].username, "admin", 64);
		strncpy(runtime[ch].password, "admin", 64);
	}
	else if(strncasecmp(runtime[ch].sys.vendor, "HDPRO", 64) == 0)
	{
		if(nf_ipcam_is_vendor_orion() == 1 || nf_ipcam_is_vendor_g4s() == 1)
		{
			strncpy(runtime[ch].username, "admin", 64);
			strncpy(runtime[ch].password, "admin", 64);
			runtime[ch].onvif.auth_method = NF_ONVIF_AUTH_DIGEST;
		}
	}


	for(auth_cnt = 0; auth_cnt < NF_ONVIF_AUTH_MAX; auth_cnt++)
	{
		temp_rtn = nf_onvif_get_service_capabilities(ch);
		if (temp_rtn == 0)
		{
			break;
		}
		if(runtime[ch].onvif.auth_method < NF_ONVIF_AUTH_MAX)
		{
			runtime[ch].onvif.auth_method++;
			if(runtime[ch].onvif.auth_method >= NF_ONVIF_AUTH_MAX)
			{
				runtime[ch].onvif.auth_method = 0;
			}

		}
		else
		{
			runtime[ch].onvif.auth_method = 0;
		}
	}

	if (temp_rtn != 0)
	{
		IPCAM_DBG(ERROR, "capability get fail CH(%d)\n", ch);
		return IPX_SEARCH_LOGIN_FAIL;
	}

	IPCAM_DBG(MINOR, "get profile token to stream(CH(%d))\n", ch);
	for(auth_cnt = 0; auth_cnt < NF_ONVIF_AUTH_MAX; auth_cnt++)
	{

		temp_rtn = nf_onvif_get_appropriate_profile(ch);

		if (temp_rtn == 0)
		{
			break;
		}

		if(runtime[ch].onvif.auth_method < NF_ONVIF_AUTH_MAX)
		{
			runtime[ch].onvif.auth_method++;
			if(runtime[ch].onvif.auth_method >= NF_ONVIF_AUTH_MAX)
			{
				runtime[ch].onvif.auth_method = 0;
			}
		}
		else
		{
			runtime[ch].onvif.auth_method = 0;
		}

	}

	if(temp_rtn != 0)
	{
		IPCAM_DBG(ERROR, "profile get fail CH(%d)\n", ch);
		return IPX_SEARCH_LOGIN_FAIL;
	}

	//temp_rtn = nf_onvif_set_vcodec(ch);

	temp_rtn = nf_onvif_get_video_capability(ch);
	if(runtime[ch].onvif.onvif_service & __OFM(NF_ONVIF_SERVICE_MEDIA2))
	{
		nf_onvif_get_video_capability_media2(ch);
	}

	if(temp_rtn == -2)
	{
		if (nf_get_running_mode())
		{
			runtime[ch].state = OPENMODE_STATE_CONFIG_FAIL;
		}
		else
		{
			nf_pnd_queue_push(ch, IPCAM_EVENT_CONFIG_FAIL, __LINE__, __FILE__);
		}
		IPCAM_DBG(WARN, "Cannot find Compatible ONVIF Resolution!!(CH:%d)\n", ch);
		return IPX_SEARCH_CONNECTION_FAILED;
	}

	runtime[ch].encoder.res_support[0] |= runtime[ch].video.resolution.resolution[0];
	runtime[ch].encoder.res_support[1] |= runtime[ch].video.resolution.resolution[1];

#if defined(_IPX_1648P)||defined(_IPX_0824VE)||defined(_IPX_0412VE)||defined(_IPX_0824ECO)||defined(_IPX_0412ECO) \
		|| defined(_IPX_1648VE3) || defined(_IPX_1648P3) || defined(_IPX_1648P3ECO)
	if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
	{
		runtime[ch].encoder.max_bitrate[0] = 4000;
	}
#else
	if(runtime[ch].encoder.max_bitrate[0] > 8000)
	{
		runtime[ch].encoder.max_bitrate[0] = 8000;
	}
	else if(runtime[ch].encoder.max_bitrate[0] <= 0)
	{
		runtime[ch].encoder.max_bitrate[0] = 8000;
	}
#endif

	if(runtime[ch].encoder.max_bitrate[1] > 1500 || runtime[ch].encoder.max_bitrate[1] <= 0)
		runtime[ch].encoder.max_bitrate[1] = 1500;

	if(runtime[ch].encoder.min_bitrate[0] < 1000)
		runtime[ch].encoder.min_bitrate[0] = 1000;

	if(runtime[ch].encoder.min_bitrate[1] < 256)
		runtime[ch].encoder.min_bitrate[1] = 256;

/*
	if(!nf_ipcam_is_vendor("CBC")) {
		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}
	
		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_VBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_VBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;	
		}
	}
*/
	runtime[ch].encoder.min_bitrate[0] = 1000;
	runtime[ch].encoder.min_bitrate[1] = 600;


#if defined(_IPX_32P4E)  || defined(_IPX_32M4E) || defined(_IPX_32P5)
	runtime[ch].encoder.max_bitrate[0] = 4000;
	runtime[ch].encoder.max_bitrate[1] = 1000;

	runtime[ch].encoder.min_bitrate[0] = 1500;
	runtime[ch].encoder.min_bitrate[1] = 600;

	if(runtime[ch].encoder.bitctrl[0] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;
	if(runtime[ch].encoder.bitctrl[1] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;
#endif
	if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
	{
		//IPXUHD-1660
		//runtime[ch].encoder.max_bitrate[0] = 8000;
		//runtime[ch].encoder.max_bitrate[1] = 2000;
		runtime[ch].encoder.max_bitrate[0] = 4000;  // 32ch max
		runtime[ch].encoder.max_bitrate[1] = 1000; 

		runtime[ch].encoder.min_bitrate[0] = 1000;
		runtime[ch].encoder.min_bitrate[1] = 600;

		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
		}
	}

	if(nf_ipcam_is_vendor_dayou())
	{
		if(strcmp(runtime[ch].sys.model,"IPFX-B40V-IRW2")==0)
		{
			printf("★★★ CAM is = IPFX-B40V-IRW2\n\n");
			runtime[ch].encoder.vcodec[0] &= ~NF_IPCAM_VCODEC_H265;
			runtime[ch].encoder.vcodec[1] &= ~NF_IPCAM_VCODEC_H265;
		}
	}

	_modify_2nd_stream_supported_res(ch);
    nf_api_ai_config_update(ch);

	return IPX_SEARCH_FOUND_AND_SET;
}

/**
 * @brief CCTV모드에서 ITX카메라 model db를 검색하여 runtime정보를 설정한다.
 * @param ch 채널 번호.
 * @return 성공시 IPX_SEARCH_FOUND_AND_SET, 나머지는 실패. @see __IPX_IPCAM_RESULTS_
 */
extern int build_management_table(int ch)
{
	int i,j;
	int result = 0;
	cam_model_info model;
	mtable *runtime = NULL;
	profile *found = NULL;
	char ip_buf[16] = {0, };
	int (*func_model_get)(cam_model_info*,int);
	int v = IPCAM_SN_VENDOR_ITX;
	int rtn;

	int major = 0, type = 0, subtype = 0, minor = 0; // Camera SDK Version
	int view_mode = 0;
	int mp=0;

	IPCAM_DBG(MAJOR, "start CH(%d)\n", ch);

	memset(&model, 0x00, sizeof(cam_model_info));

#if defined(ENABLE_PROJECT_KMW)||defined(ENABLE_PROJECT_KUMMI)
	result = cam_get_model_info_nopnd(&model, ch);
#else
#if 0
	for (i = 0; i < 3; i++)
	{
		memset(&model, 0x00, sizeof(cam_model_info));
		func_model_get = get_model_funcs[i];
		result = func_model_get(&model, ch);
		if (result > 0) { break; }
	}
#endif
#if 0
	result = cam_get_model_info_by_default(&model, ch);
#else
	runtime = get_runtime();

	char userID[64];
	char userPW[64];
	memset(userID, 0x00, 64);
	memset(userPW, 0x00, 64);

	nf_ipcam_get_default_login_info(userID, userPW);

	result = cam_get_model_info_raw(&model, runtime[ch].sys.ipaddr, runtime[ch].admin_http, userID, userPW, &runtime[ch].sys.use_ssl);
		printf("\e[104m [%s][%d] result(%d)  \e[0m\n", __func__, __LINE__, result );
	strncpy(runtime[ch].username, userID, 64);
	strncpy(runtime[ch].password, userPW, 64);
#endif
	if (result <= 0) {
		result = nvs_get_model_info(&model, ch, 0);
		printf("\e[104m [%s][%d] result(%d)  \e[0m\n", __func__, __LINE__, result );
	}
	if (result == 1)
	{
#if 0
		result = cam_get_model_info_by_sysdb(&model, ch);
#else
		{
			gchar key_u[64];
			gchar key_p[64];
			gchar *u,*p;
			snprintf(key_u, 64, "cam.logininfo.L%d.id", ch);
			snprintf(key_p, 64, "cam.logininfo.L%d.pwd", ch);
			u = nf_sysdb_get_str_nocopy(key_u);
			p = nf_sysdb_get_str_nocopy(key_p);
			strncpy(runtime[ch].username, u, 64);
			strncpy(runtime[ch].password, p, 64);
		}
		result = cam_get_model_info_raw(&model, runtime[ch].sys.ipaddr, runtime[ch].admin_http, runtime[ch].username, runtime[ch].password, &runtime[ch].sys.use_ssl);
		printf("\e[104m [%s][%d] result(%d)  \e[0m\n", __func__, __LINE__, result );
#endif
		if (result <= 0) {
			result = nvs_get_model_info(&model, ch, 1);
		printf("\e[104m [%s][%d] result(%d)  \e[0m\n", __func__, __LINE__, result );
		}
	}
#endif
	if (result <= 0)
	{
		return IPX_SEARCH_CONNECTION_FAILED;
	}
	else if (result == 1)
	{
		return IPX_SEARCH_LOGIN_FAIL;
	}

	/* Blacklist IP Camera blocked not to be connected */
	if (nf_sysman_get_fwver_vendor() == 46)	// Novus
	{
		if (strcmp(model.vendor, "Novus") != 0)
		{
			IPCAM_DBG(MINOR, "Blacklist IP Camera(%s, %s)\n", model.vendor, model.name);
			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
	}

	IPCAM_DBG(MINOR, "CH(%d) MODEL name(%s) std(%s) fw(%s) fw_std(%s) vendor(%s) sdk(%s)\n",
			ch, model.name, model.stdver,
			model.swver, model.swver2, model.vendor, model.sdkver);

	/* IPCam error - Exception handling */
	if (strncmp(model.name, "\%28null\%29", 10) == 0)
	{
		return IPX_SEARCH_CONNECTION_FAILED;
	}

	//IPCAM_DBG(MINOR, "Model db has [%d] entries\n", modeldb_cnt);
	for (i = 0; i < modeldb_cnt; i++)
	{
		if (strcmp(ipcam_model_db[i].name, model.name) == 0)
		{
			break;
		}
	}
	for (j = 0; j < modeldb_cnt; j++)
	{
		if (strcmp(ipcam_model_db[j].name, model.stdver) == 0)
		{
			break;
		}
	}

	if (i >= modeldb_cnt && j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) model unsupported..\n", ch);
		sscanf(model.sdkver, "%d.%d.%d.%d", &major, &type, &subtype, &minor);

		basic_setup_unsupported_camera_cctv(ch, model);

		rtn = nf_ipcam_get_json_capabilities(ch);
		if(rtn != 0)
		{
			printf("CH(%d) model is not supprted camera capabilities api...\n", ch);
			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
		else
			goto default_settings;  
	}

	if (j >= modeldb_cnt)
	{
		IPCAM_DBG(WARN, "CH(%d) Cam SW version incompatible", ch);
	}
	else
	{
		i = j;
	}

	found = (profile*) &ipcam_model_db[i];

	runtime[ch].func = found->func;
	runtime[ch].profile_id = i;

#if (!defined(ENABLE_PROJECT_KMW))&&(!defined(ENABLE_PROJECT_KUMMI))
	runtime[ch].sys.http_port = runtime[ch].admin_http;
	runtime[ch].sys.rtsp_port[0] = runtime[ch].admin_rtsp;
	runtime[ch].sys.rtsp_port[1] = runtime[ch].admin_rtsp;
	runtime[ch].sys.rtsp_port[2] = 0;

	runtime[ch].sys.model_code = found->model_code;
#endif
	runtime[ch].sys.rx_method = NF_IPCAM_RX_METHOD_RTSP_TCP;
	strncpy(runtime[ch].sys.model, model.name, 64);
	strncpy(runtime[ch].sys.swver, model.swver, 64);
	strncpy(runtime[ch].sys.swver2, model.swver2, 64);
	strncpy(runtime[ch].sys.vendor, model.vendor, 64);
	strncpy(runtime[ch].sys.sdkver, model.sdkver, 64);
	strncpy(runtime[ch].sys.stdver, model.stdver, 64);

	/*	NPT2 - updated zoom module ver. */
	if(model.zoom_module_name != NULL)
		strncpy(runtime[ch].sys.zoom_module_name, model.zoom_module_name, 63);
	if(model.zoom_module_fwver != NULL)
		strncpy(runtime[ch].sys.zoom_module_fwver, model.zoom_module_fwver, 63);

	runtime[ch].sys.type = model.type;
	runtime[ch].sys.nvs_sub_ch = model.nvs_sub_ch;

	memcpy(&runtime[ch].video, &model_video_profiles[found->video],  sizeof(video_t));
	memcpy(&runtime[ch].encoder, &model_encoder_profiles[found->encoder],  sizeof(encoder_t));
	memcpy(&runtime[ch].audio, &model_audio_profiles[found->audio],  sizeof(audio_t));
	memcpy(&runtime[ch].image, &model_image_profiles[found->image],  sizeof(image_t));
	memcpy(&runtime[ch].ptz,   &model_ptz_profiles[found->ptz],      sizeof(ptz_t));
	memcpy(&runtime[ch].alarm, &model_alarm_profiles[found->alarm],  sizeof(alarm_t));
	memcpy(&runtime[ch].motion,&model_motion_profiles[found->motion],sizeof(motion_t));
	memcpy(&runtime[ch].focus,	   &model_focus_profiles[found->focus],sizeof(focus_t));

	if( runtime[ch].focus.supported	!= 0 )
	{		
		focus_comp_info fcinfo;
		memset(&fcinfo, 0x00, sizeof(fcinfo));
		if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
		{
			runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
			runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
			runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
			runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
			runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
		}

	}

	if (runtime[ch].sys.type == SYSTEM_DEVICE_NVS) {
		runtime[ch].state = MGMT_STATE_UNLINKED;
		if (model.vstype == 1) {
			runtime[ch].video.resolution.supported = NF_IPCAM_RES_704x576;
			runtime[ch].video.resolution.resolution[0] = NF_IPCAM_RES_704x576;
		}
	}

	get_ipstr(runtime[ch].sys.ipaddr, ip_buf);
	for (i = 0; i < runtime[ch].video.stream_cnt; i++)
	{
		snprintf(runtime[ch].sys.rtsp_url[i], 256, model_rtsp_addrs[found->rtsp[i]], ip_buf);
	}

	memcpy(&runtime[ch].funcs, &model_funcs[found->funcs], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
	runtime[ch].recv_handler = model_recv_handlers[found->recv_handler];

	sscanf(model.sdkver, "%d.%d.%d.%d", &major, &type, &subtype, &minor);

	// image profile change : MaxShutter Speed max value = 5000 
	if(type == ITX_CAM_SDK_TYPE_HS && minor >= 1)
	{
		switch(found->image)
		{
			case 12 : memcpy(&runtime[ch].image, &model_image_profiles[31], sizeof(image_t)); break;
			case 13 : memcpy(&runtime[ch].image, &model_image_profiles[32], sizeof(image_t)); break;
			case 16 : memcpy(&runtime[ch].image, &model_image_profiles[33], sizeof(image_t)); break;
			case 17 : memcpy(&runtime[ch].image, &model_image_profiles[34], sizeof(image_t)); break;
			case 19 : memcpy(&runtime[ch].image, &model_image_profiles[35], sizeof(image_t)); break;
			case 20 : memcpy(&runtime[ch].image, &model_image_profiles[36], sizeof(image_t)); break;
			case 21 : memcpy(&runtime[ch].image, &model_image_profiles[37], sizeof(image_t)); break;
		}
	}

default_settings:;
	if(ip_buf[0] == 0){
		get_ipstr(runtime[ch].sys.ipaddr, ip_buf);
	}

	//CBC H265 codec remove exception code
	if(nf_ipcam_is_vendor("CBC"))
	{
		for (i = 0; i < runtime[ch].video.stream_cnt; i++){
			if(runtime[ch].encoder.vcodec[i] & NF_IPCAM_VCODEC_H264){
				runtime[ch].video.vcodec[i] = NF_IPCAM_VCODEC_H264;	
			}
		}

		/*
		runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H264;	
		runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H264;

		runtime[ch].encoder.vcodec[0] &= ~(NF_IPCAM_VCODEC_H265);
		runtime[ch].encoder.vcodec[1] &= ~(NF_IPCAM_VCODEC_H265);
		*/
	}

	if(strstr(runtime[ch].sys.stdver, "CFE")){
		view_mode = cam_get_view_mode(ch);
        if(cam_get_encode_mode(ch) > 0 || view_mode == 0){
			if(view_mode == -3 ) // Not support view_mode
			{
				cam_set_fisheye_init_legacy(ch,0); //legacy fisheye config
			}
			else
			{
			    cam_set_fisheye_init(ch, 0, 1); // default setting enc_mode = 0('fisheye'), view_mode = 1('Multi')
			}
            return IPX_SEARCH_CONNECTION_FAILED;
        }
    }

	/* FIXME. Temporary exception */
	if ((strncmp(runtime[ch].sys.vendor, "GANZ", 4) == 0 && strncmp(runtime[ch].sys.model, "ZN", 2) == 0)
	 || (strncmp(runtime[ch].sys.vendor, "UTT", 3) == 0 && strncmp(runtime[ch].sys.model, "UT", 2) == 0))
	{
		snprintf(runtime[ch].sys.rtsp_url[0], 256, model_rtsp_addrs[3], ip_buf);
		snprintf(runtime[ch].sys.rtsp_url[1], 256, model_rtsp_addrs[4], ip_buf);
		v = IPCAM_SN_VENDOR_CBC;
	}

	/* ITX Camera SN Get */
	struct sn_info info;
	if(cam_sn_get(&info, ch, v) == 0)
	{
		printf("SN INFO CH(%d): >> %s/%s/%s/%s/%s/%s/%s/%s/%s\n", ch,
				info.vendor,
				info.nation,
				info.date,
				info.mega,
				info.lens,
				info.heater,
				info.irled,
				info.sensor,
				info.ads);

		// Adaptive IR || colorvu(include anti-exposure-mode)
		if(info.irled[0] == 'A' || info.irled[0] == 'W')
		{
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
			runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
		    if(type == ITX_CAM_SDK_TYPE_HS) //HISILICON 
			{
				runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF;

				if(nf_ipcam_is_vendor_videcon())
					runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}
			else
			{
				runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}
		}

		// Adjust DNN’s Sensitivity
		if(info.ads[0] == 'D')
		{
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
			runtime[ch].image.dnn_sense_ntod.min = 3;
			runtime[ch].image.dnn_sense_ntod.max = 10;
			runtime[ch].image.dnn_sense_ntod.value = 7;
			runtime[ch].image.dnn_sense_ntod.diff = 3;
			runtime[ch].image.dnn_sense_ntod.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_DTON;

			runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_DTON;
			runtime[ch].image.dnn_sense_dton.min = 0;
			runtime[ch].image.dnn_sense_dton.max = 7;
			runtime[ch].image.dnn_sense_dton.value = 4;
			runtime[ch].image.dnn_sense_dton.diff = -3;
			runtime[ch].image.dnn_sense_dton.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_NTOD;

			runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_D2N] = (gpointer)&cam_set_dnn_adjust_d2n;
			runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_N2D] = (gpointer)&cam_set_dnn_adjust_n2d;
		}
		if(strstr(info.vendor, "CBC") != NULL)
		{
			if(strcmp(runtime[ch].sys.stdver, "INDi-2005PR") == 0 ||
				strcmp(runtime[ch].sys.stdver,"IND-2005PR") == 0 ||
				strcmp(runtime[ch].sys.stdver,"INB-2005PR") == 0)
			{
				runtime[ch].image.exposure.value = NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION_INX;
				runtime[ch].image.wd.value = NF_IPCAM_WDR_MODE_ITX_LOW; 
				runtime[ch].image.brightness.value = 20;
				runtime[ch].image.color.value = 13;
			}
		}

		if(info.sensor[0] == '9' && type == ITX_CAM_SDK_TYPE_HS && minor > 5)//IMX291 && HS && SDK ver
		{
			if(strncmp(runtime[ch].sys.stdver, "IND", 3) == 0 
					|| strncmp(runtime[ch].sys.stdver, "INB", 3) == 0)	//INxH 2M
			{
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNR_AUTO_SMART;
				runtime[ch].image.dnr_ctr.support |= NF_IPCAM_DNR_MODE_AUTO_SMART;
			}
		}
	}

	if(runtime[ch].image.supported & NF_IPCAM_IMAGE_DNN)
	{
		runtime[ch].image.day_night.support |= NF_IPCAM_IMAGE_DN_SCHEDULE;
	}

	if(major < 6)
	{
		if (strncmp(runtime[ch].sys.stdver, "NPT", 3) == 0)
		{
			if(strcmp(model.sdkver, "1.0.0.4") >= 0)
			{
				// FIXME. by model codes
				//runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				//memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[2], sizeof(pmask_t));
				//runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&npt_set_pmask;

				//add motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));
			}
			else
			{
				runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_WDR);
				memset(&runtime[ch].image.wd, 0x00, sizeof(modes));
				memset(&runtime[ch].image.focus_mode, 0x00, sizeof(modes));
			}
		}
		else if(type == ITX_CAM_SDK_TYPE_HS)
		{
			        if(runtime[ch].func & NF_IPCAM_FUNC_PRIVACY_MASK)
				{
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[3], sizeof(pmask_t));
				}

			if(minor >= 6)
			{
				if (strncmp(runtime[ch].sys.swver, "38100", 5) == 0) //3516C
				{
					//registration ROI Function
					runtime[ch].func |= NF_IPCAM_FUNC_ROI;
					memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[2], sizeof(roi_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_ROI] = (gpointer)&cam_set_roi_area;

					//DEFOG
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;

					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_LOW;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_MID;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HI_HIGH;
					runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_HI_OFF;
				}
				if (strncmp(runtime[ch].sys.swver, "40300", 5) == 0 || strncmp(runtime[ch].sys.swver, "48100", 5) == 0 //ITX 3516A/D
						||  strncmp(runtime[ch].sys.swver, "66000", 5) == 0) //ICA 3516D  
				{
					//registration ROI Function
					runtime[ch].func |= NF_IPCAM_FUNC_ROI;

					if (strncmp(runtime[ch].sys.swver, "40300", 5) == 0)
						memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[1], sizeof(roi_t));
					else
						memcpy(&runtime[ch].roi_area, &model_roi_area_profiles[3], sizeof(roi_t));

					runtime[ch].funcs[NF_IPCAM_TYPE_SET_ROI] = (gpointer)&cam_set_roi_area;

					// VBR+
					runtime[ch].encoder.bitctrl[0] |= NF_IPCAM_BITRATE_CONTROL_VBR_PLUS;

					if(strncmp(runtime[ch].sys.swver, "66000", 5) == 0)
					{  
						// VA FUNCTION
						runtime[ch].func |= NF_IPCAM_FUNC_VA;
						runtime[ch].funcs[NF_IPCAM_TYPE_SET_RESET_VA] = (gpointer)&cam_set_reset_va;
						runtime[ch].funcs[NF_IPCAM_TYPE_SET_VA_CONFIG] = (gpointer)&cam_set_va_config;
					}
				}
			}

			if(minor > 6)
			{
				//registration External mode 
				if(strstr(runtime[ch].sys.stdver, "INX-5007P") != NULL || 
						strstr(runtime[ch].sys.stdver, "NCX-2003P") != NULL) 
				{
					runtime[ch].image.day_night.support |= 	NF_IPCAM_IRCUT_MODE_ITX_EXTERNAL;
				}
			}
		}
		else
		{
			if(strncmp(runtime[ch].sys.stdver, "IN", 2) == 0)
			{
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));

				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 3;
				runtime[ch].image.dnn_sense_ntod.max = 10;
				runtime[ch].image.dnn_sense_ntod.value = 7;
				runtime[ch].image.dnn_sense_ntod.diff = 3;
				runtime[ch].image.dnn_sense_ntod.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_DTON;

				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_DTON;
				runtime[ch].image.dnn_sense_dton.min = 0;
				runtime[ch].image.dnn_sense_dton.max = 7;
				runtime[ch].image.dnn_sense_dton.value = 4;
				runtime[ch].image.dnn_sense_dton.diff = -3;
				runtime[ch].image.dnn_sense_dton.dep_cate = NF_IPCAM_IMAGE_DNN_SENSE_NTOD;

				runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_D2N] = (gpointer)&cam_set_dnn_adjust_d2n;
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_ADJUST_N2D] = (gpointer)&cam_set_dnn_adjust_n2d;

				//runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
				//runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
				//runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;

				if(strstr(runtime[ch].sys.stdver, "-3005PR") != NULL)
				{
					if (strcmp(model.sdkver, "1.0.0.6") >= 0)
					{
						runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX);
						runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_MID);
					}
				}
			}
			else
			{
				if (strcmp(model.sdkver, "1.0.0.3") >= 0)
				{
					// FIXME. by model codes
					runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;
				}

				if (strcmp(model.sdkver, "1.0.0.4") >= 0)
				{
					runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.slow_shutter.support |= (NF_IPCAM_IMAGE_SLSH_MODE_X4 | NF_IPCAM_IMAGE_SLSH_MODE_X8);
				}
				else
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					runtime[ch].image.onthefly &= ~(NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
					memset(&runtime[ch].image.anti_flicker, 0x00, sizeof(modes));
					memset(&runtime[ch].image.max_shutter, 0x00, sizeof(modes));
				}

				if (strcmp(model.sdkver, "3.0.0.4") >= 0)
				{
					runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
					runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
					runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
						NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
						NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
					runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);

					runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
					runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);
				}

				if(strncmp(runtime[ch].sys.stdver,"NMD", 3) == 0 || strncmp(runtime[ch].sys.stdver,"NMX", 3) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH);
					if(strncmp(runtime[ch].sys.stdver,"NMDi", 4) == 0)
					{
						runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
					}
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
				}

				if(strncmp(runtime[ch].sys.stdver,"NMB", 3) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
				}

			}
		}

		//vendor for CBC (MAX AGC ISSUE)
		if(strstr(info.vendor, "CBC") != NULL)
		{
			if(major >=  5 && minor >= 8)
			{
				//set max_agc
				memset(&runtime[ch].image.max_agc, 0x00, sizeof(modes));

				runtime[ch].image.max_agc.support = 
				(NF_IPCAM_IMAGE_MAGC_MODE_CBC_0 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_1 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_2 |	NF_IPCAM_IMAGE_MAGC_MODE_CBC_3 |
			     NF_IPCAM_IMAGE_MAGC_MODE_CBC_4 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_5 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_6 |	NF_IPCAM_IMAGE_MAGC_MODE_CBC_7 |
				 NF_IPCAM_IMAGE_MAGC_MODE_CBC_8 | NF_IPCAM_IMAGE_MAGC_MODE_CBC_9);
					
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_CBC_4);
			}
		}
	}
	else
	{
		if (type == ITX_CAM_SDK_TYPE_NPT2)
		{
			if(subtype == 0) // NPT2 x30 EH Model
			{
				// Night to Day Sensitivity
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 0;
				runtime[ch].image.dnn_sense_ntod.max = 25;
				runtime[ch].image.dnn_sense_ntod.value = 20;

				// IR Correction
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_IR_CORRECTION;
				runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_ON;
				runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_OFF;
				runtime[ch].image.ir_correction.value = NF_IPCAM_IMAGE_IR_CORRECTION_OFF;

				// Focus Near Limit
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_FOCUS_LIMIT;
				runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_30;
				runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_100;
				runtime[ch].image.focus_limit.value = NF_IPCAM_IMAGE_FOCUS_LIMIT_100;

				// Stabilizer
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
				runtime[ch].image.stabilizer.value |= NF_IPCAM_IMAGE_STABILIZER_OFF;

				// Auto White Balance
				runtime[ch].image.wb.support |= NF_IPCAM_WB_MODE_ITX_AUTO_W;
				runtime[ch].image.wb.value = NF_IPCAM_WB_MODE_ITX_AUTO_W;

				//Motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));
			}
			if(subtype == 1) // NPT2 x10, x20/x30 EV Model, 
			{
				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_COLOR);
					runtime[ch].image.exposure.support = (NF_IPCAM_IMAGE_EXP_MODE_AUTO_NPT_X10 | NF_IPCAM_IMAGE_EXP_MODE_MANUAL_NPT_X10);
					runtime[ch].image.exposure.value = NF_IPCAM_IMAGE_EXP_MODE_AUTO_NPT_X10;

					runtime[ch].image.agc.max = 18;
					runtime[ch].image.eshutter_speed.max = 60000;

					if(strstr(runtime[ch].sys.zoom_module_name, "MC-108") != NULL)
					//|| (atoi(runtime[ch].sys.zoom_module_fwver) >= 13 ) /* fwver check */
					{
						runtime[ch].image.eshutter_speed.max = 30000;
					}

					runtime[ch].image.sharpness.max = 10;
				}

				//Motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));

				//runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				//runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&npt_set_pmask;
				//memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));

				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_LOW;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_MID;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HIGH;

				if(strstr(runtime[ch].sys.stdver, "-2003P30-EV") != NULL)
				{
					runtime[ch].image.defog.support = NF_IPCAM_IMAGE_DEFOG_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_ON;

					runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
					runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
					runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
					runtime[ch].image.stabilizer.value = NF_IPCAM_IMAGE_STABILIZER_OFF;
				}

				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.supported &= ~(NF_IPCAM_IMAGE_MAXAGC);

					runtime[ch].image.defog.support = NF_IPCAM_IMAGE_DEFOG_X10_OFF;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_LOW;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_MID;
					runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_X10_HIGH;
				}

				// HLC
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_HLC;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_OFF;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_LOW;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_MID;
				runtime[ch].image.hlc.support |= NF_IPCAM_IMAGE_HLC_HIGH;

				if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
				{
					runtime[ch].image.hlc.support = NF_IPCAM_HLC_X10_OFF;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_LOW;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_MID;
					runtime[ch].image.hlc.support |= NF_IPCAM_HLC_X10_HIGH;
				}

				// Night to Day Sensitivity
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DNN_SENSE_NTOD;
				runtime[ch].image.dnn_sense_ntod.min = 0;
				runtime[ch].image.dnn_sense_ntod.max = 25;
				runtime[ch].image.dnn_sense_ntod.value = 20;

				// WDR
				runtime[ch].image.wd.support = NF_IPCAM_WDR_MODE_ITX_OFF |
					NF_IPCAM_WDR_MODE_ITX_NPT_LOW |
					NF_IPCAM_WDR_MODE_ITX_NPT_MID |
					NF_IPCAM_WDR_MODE_ITX_NPT_HIGH;
				runtime[ch].image.wd.value = NF_IPCAM_WDR_MODE_ITX_OFF;

				if(strstr(runtime[ch].sys.stdver, "-2003P20-EV") != NULL ||
					strstr(runtime[ch].sys.stdver, "-2003P30-EV") != NULL)
				{
					// IR Correction
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_IR_CORRECTION;
					runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_ON;
					runtime[ch].image.ir_correction.support |= NF_IPCAM_IMAGE_IR_CORRECTION_OFF;
					runtime[ch].image.ir_correction.value = NF_IPCAM_IMAGE_IR_CORRECTION_OFF;

					// Focus Near Limit
					runtime[ch].image.supported |= NF_IPCAM_IMAGE_FOCUS_LIMIT;
					runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_30;
					runtime[ch].image.focus_limit.support |= NF_IPCAM_IMAGE_FOCUS_LIMIT_100;
					runtime[ch].image.focus_limit.value = NF_IPCAM_IMAGE_FOCUS_LIMIT_100;

					// Auto White Balance
					runtime[ch].image.wb.support |= NF_IPCAM_WB_MODE_ITX_AUTO_W;
					runtime[ch].image.wb.value = NF_IPCAM_WB_MODE_ITX_AUTO_W;
				
					//Motion
					memcpy(&runtime[ch].motion,&model_motion_profiles[5],sizeof(motion_t));
				}
			}


			// IR Cut Filter
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_IRCUTM;

			// Anti-Flicker
			runtime[ch].image.supported |= NF_IPCAM_IMAGE_ANTIFLICKER;

			if(strstr(runtime[ch].sys.stdver, "-2003P10") != NULL)
			{
				runtime[ch].image.anti_flicker.support = NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_ON;
				runtime[ch].image.anti_flicker.support |= NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_OFF;
				runtime[ch].image.anti_flicker.value = NF_IPCAM_ANTI_FLICKER_NPT_X10_MODE_OFF;
			
				//Motion
				memcpy(&runtime[ch].motion,&model_motion_profiles[11],sizeof(motion_t));
			}

		}
		if (type == ITX_CAM_SDK_TYPE_IRPTZ)
		{
			if(strstr(runtime[ch].sys.stdver, "-2003R20") != NULL)
			{
				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_LOW;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_MID;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_HIGH;
				runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_OFF;

			}
			if(strstr(runtime[ch].sys.stdver, "-2003R30") != NULL)
			{
				// DEFOG
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_DEFOG;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_OFF;
				runtime[ch].image.defog.support |= NF_IPCAM_IMAGE_DEFOG_ON;
				runtime[ch].image.defog.value = NF_IPCAM_IMAGE_DEFOG_OFF;

				// Stabilizer
				runtime[ch].image.supported |= NF_IPCAM_IMAGE_STABILIZER; 
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_ON;
				runtime[ch].image.stabilizer.support |= NF_IPCAM_IMAGE_STABILIZER_OFF;
				runtime[ch].image.stabilizer.value |= NF_IPCAM_IMAGE_STABILIZER_OFF;
			}

		}

		if(type == ITX_CAM_SDK_TYPE_TI368 || type == ITX_CAM_SDK_TYPE_TI385 || type == ITX_CAM_SDK_TYPE_DMVAI)
		{
			if(type == ITX_CAM_SDK_TYPE_TI385)
			{
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));

				if(strstr(runtime[ch].sys.stdver, "-3005PR") != NULL)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX);
					runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_MID);
				}

				//runtime[ch].image.supported |= NF_IPCAM_IMAGE_ADAPTIVEIR;
				//runtime[ch].image.adaptive_ir.support = (NF_IPCAM_IMAGE_ADAPTIVE_IR_OFF | NF_IPCAM_IMAGE_ADAPTIVE_IR_ON);
				//runtime[ch].image.adaptive_ir.value = NF_IPCAM_IMAGE_ADAPTIVE_IR_ON;
			}


			if(type == ITX_CAM_SDK_TYPE_TI368)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;

				runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
				runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);

				runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
				runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
				runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
					NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
					NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
				runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);


				if(strncmp(info.lens, "PT", 2) == 0 || 	strncmp(info.lens, "P2", 2) == 0 || strncmp(info.lens, "ZZ", 2) == 0 || strncmp(info.lens, "P3", 2) == 0)
				{
					runtime[ch].focus.dnn_comp.value = 1;

					if(strncmp(info.vendor, "KON", 3) == 0 || strncmp(info.lens, "P3", 2) == 0)
						runtime[ch].focus.dnn_comp.value = 0;

					runtime[ch].focus.supported |= NF_IPCAM_FOCUS_DNN_COMP;
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_FOCUS_COMP] = cam_set_focus_comp;
					focus_comp_info fcinfo;
					memset(&fcinfo, 0x00, sizeof(fcinfo));
					if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
					{
						runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
						runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
						runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
						runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
						runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
					}

					if(nf_sysman_get_fwver_vendor() == 65 || nf_sysman_get_fwver_vendor() == 98) // Takenaka
						runtime[ch].focus.dnn_comp.value = 0;
				}

				if(strncmp(runtime[ch].sys.stdver, "NMX", 3) == 0)
				{
					focus_comp_info fcinfo;
					memset(&fcinfo, 0x00, sizeof(fcinfo));
					if(cam_get_focus_comp(&fcinfo, ch) == IPCAM_SETUP_RTN_DONE)
					{
						runtime[ch].focus.maskarea[0].value = fcinfo.maskarea[0];
						runtime[ch].focus.areatx[0].value = fcinfo.areatx[0];
						runtime[ch].focus.areaty[0].value = fcinfo.areaty[0];
						runtime[ch].focus.areabx[0].value = fcinfo.areabx[0];
						runtime[ch].focus.areaby[0].value = fcinfo.areaby[0];
					}

					runtime[ch].focus.supported |= NF_IPCAM_FOCUS_TEM_COMP;
					if(strncmp(info.vendor, "KMW", 3) == 0)
						runtime[ch].focus.tem_comp.value = 0;
					else
						runtime[ch].focus.tem_comp.value = 1;

					runtime[ch].focus.dnn_comp.value = 0;
					runtime[ch].focus.supported &= ~(NF_IPCAM_FOCUS_DNN_COMP);
					if(strncmp(info.irled, "C", 1) == 0)
					{
						runtime[ch].focus.dnn_comp.value = 1;
						runtime[ch].focus.supported |= NF_IPCAM_FOCUS_DNN_COMP;
					}

					if(nf_sysman_get_fwver_vendor() == 65 || nf_sysman_get_fwver_vendor() == 98) // Takenaka
					{
						runtime[ch].focus.dnn_comp.value = 0;
						runtime[ch].focus.tem_comp.value = 0;
					}

					runtime[ch].funcs[NF_IPCAM_TYPE_SET_FOCUS_COMP] = cam_set_focus_comp;
				}

			}

			if (type == ITX_CAM_SDK_TYPE_DMVAI)
			{
				runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
				memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[1], sizeof(pmask_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&cam_set_pmask;

				runtime[ch].image.supported |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.onthefly |= (NF_IPCAM_IMAGE_ANTIFLICKER | NF_IPCAM_IMAGE_MAX_SHUTTER);
				runtime[ch].image.slow_shutter.support = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF | NF_IPCAM_IMAGE_SLSH_MODE2_ON | NF_IPCAM_IMAGE_SLSH_MODE2_X4 | NF_IPCAM_IMAGE_SLSH_MODE2_X8);
				runtime[ch].image.slow_shutter.value = (NF_IPCAM_IMAGE_SLSH_MODE2_OFF);

				runtime[ch].image.max_agc.support |= NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_MAX;
				runtime[ch].image.exposure.support |= NF_IPCAM_IMAGE_EXP_MODE_AUTO_MOTION;
				runtime[ch].image.blc.support |= NF_IPCAM_IMAGE_BLC_OFF | NF_IPCAM_IMAGE_BLC_ADAPTIVE |
					NF_IPCAM_IMAGE_BLC_ZONE_LOWER | NF_IPCAM_IMAGE_BLC_ZONE_MIDDLE | NF_IPCAM_IMAGE_BLC_ZONE_UPPER |
					NF_IPCAM_IMAGE_BLC_ZONE_LEFT | NF_IPCAM_IMAGE_BLC_ZONE_RIGHT;
				runtime[ch].image.blc.support &= ~(NF_IPCAM_IMAGE_BLC_ON);
			}

			if(strncmp(runtime[ch].sys.stdver,"NMD", 3) == 0 || strncmp(runtime[ch].sys.stdver,"NMX", 3) == 0)
			{
				runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH);
				if(strncmp(runtime[ch].sys.stdver,"NMDi", 4) == 0)
				{
					runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
				}
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
			}

			if(strncmp(runtime[ch].sys.stdver,"NMB", 3) == 0)
			{
				runtime[ch].image.max_agc.support = (NF_IPCAM_IMAGE_MAGC_MODE_LOW | NF_IPCAM_IMAGE_MAGC_MODE_MID | NF_IPCAM_IMAGE_MAGC_MODE_HIGH | NF_IPCAM_IMAGE_MAGC_MODE_MAX );
				runtime[ch].image.max_agc.value = (NF_IPCAM_IMAGE_MAGC_MODE_LOW);
			}
		}
	}
/*
	if(!nf_ipcam_is_vendor("CBC")) {
		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}
	
		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_VBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_VBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;	
		}
	}
*/
	//min bitrate modify
	runtime[ch].encoder.min_bitrate[0] = 1000;
	runtime[ch].encoder.min_bitrate[1] = 600;

	if(runtime[ch].image.supported & NF_IPCAM_IMAGE_COLORVU){
		runtime[ch].image.colorvu_level.min = 1;
		runtime[ch].image.colorvu_level.max = 200;
		runtime[ch].image.colorvu_level.value = 200;
		runtime[ch].image.colorvu_ctrl.value = NF_IPCAM_COLORVU_CTRL_AUTO;
	}

	//ipcam ntp timesync setting 
	if(runtime[ch].funcs[NF_IPCAM_TYPE_INIT] == NULL)
		runtime[ch].funcs[NF_IPCAM_TYPE_INIT] = (gpointer)&cam_set_time_info;

#if defined(_IPX_32P4E)  || defined(_IPX_32M4E) || defined(_IPX_32P5)
	runtime[ch].encoder.max_bitrate[0] = 4000;
	runtime[ch].encoder.max_bitrate[1] = 1000;

	runtime[ch].encoder.min_bitrate[0] = 1500;
	runtime[ch].encoder.min_bitrate[1] = 600;

	if(runtime[ch].encoder.bitctrl[0] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;
	if(runtime[ch].encoder.bitctrl[1] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;
#endif
	if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
	{
		/*
		if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
		{
			runtime[ch].encoder.max_bitrate[0] = 4000;
		}
		if(runtime[ch].encoder.max_bitrate[1] > 1000 || runtime[ch].encoder.max_bitrate[1] <= 0)
		{
			runtime[ch].encoder.max_bitrate[1] = 1000;
		}
		*/

		//IPXUHD-1660
		//runtime[ch].encoder.max_bitrate[0] = 8000;
		//runtime[ch].encoder.max_bitrate[1] = 2000;
		runtime[ch].encoder.max_bitrate[0] = 4000; //32ch
		runtime[ch].encoder.max_bitrate[1] = 1000;

		runtime[ch].encoder.min_bitrate[0] = 1000;
		runtime[ch].encoder.min_bitrate[1] = 600;

		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
			&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
		}
	}

	if(nf_ipcam_is_vendor_dayou())
	{
		if(strcmp(runtime[ch].sys.model, "IPFX-B40V-IRW2")==0)
		{
			runtime[ch].encoder.vcodec[0] &= ~NF_IPCAM_VCODEC_H265;
			runtime[ch].encoder.vcodec[1] &= ~NF_IPCAM_VCODEC_H265;
		}
	}
	if(nf_ipcam_is_vendor_zicom())
	{
		// resolution setting
		runtime[ch].video.resolution.resolution[0] = _get_max_resolution(ch, 0);

		// bitrate setting
		mp = _get_mp_from_res(runtime[ch].video.resolution.resolution[0]);
		if(mp == 8)
		{
			runtime[ch].video.bitrate[0].value = 4000;
		}
		else if(mp == 5)
		{
			runtime[ch].video.bitrate[0].value = 4000;
		}
		else if(mp == 2)
		{
			runtime[ch].video.bitrate[0].value = 2000;
		}
		else
		{
			runtime[ch].video.bitrate[0].value = runtime[ch].encoder.max_bitrate[0] >= 4000 ? 4000 : runtime[ch].encoder.max_bitrate[0]; // itx basic set 
		}


		// codec setting
		runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H264;
		runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H264;

		/*
		// smart motion setting
		if(runtime[ch].motion.smart_motion_support)
		{
			runtime[ch].motion.smart_motion_enable = 1;
			for(i=0; i<runtime[ch].motion.smart_motion_option_size; i++)
			{
				runtime[ch].motion.smart_motion_options[i].threshold = 50;
			}
			runtime[ch].motion.sensitivity.value = 5;
		}
		*/

	}

	// 32ch 2nd stream modify 
	_modify_2nd_stream_supported_res(ch);
    nf_api_ai_config_update(ch);

	return IPX_SEARCH_FOUND_AND_SET;
}

/**
 * @brief CCTV모드에서 ONVIF카메라 model db를 검색하여 runtime정보를 설정한다.
 * @param ch 채널 번호.
 * @return DB검색 성공시 IPX_SEARCH_FOUND_AND_SET, 실패시 IPX_SEARCH_FOUND_NOT_SUPPORTED.
 *
 * ONVIF카메라의 경우 db검색 실패하여도 계속 접속루틴은 진행시킨다.
 */
extern int build_management_table_onvif(int ch)
{
	int i;
	int result = 0;
	mtable *runtime = NULL;
	profile *found = NULL;
	char ip_buf[16];

	IPCAM_DBG(MAJOR, "start CH(%d)\n", ch);
	//IPCAM_DBG(MINOR, "Model db has [%d] entries\n", onvif_modeldb_cnt);

	runtime = get_runtime();
	if (runtime == NULL) { return IPX_SEARCH_FOUND_NOT_SUPPORTED; }

	/* onthefly query added */
	/*
	{
		int resol, fps, bitrate;
		int rtn = get_onvif_onthefly_db(runtime[ch].sys.vendor,
				runtime[ch].sys.model,
				runtime[ch].sys.swver, &resol, &fps, &bitrate);

		if(rtn == 0)
		{
			runtime[ch].onvif.query_onthefly_state = 1;
		}
		else
		{
			if(fps)
			{
				runtime[ch].video.supported |= VIDEO_SETUP_FPS;
				runtime[ch].video.onthefly |= VIDEO_SETUP_FPS;
			}
			if(bitrate)
			{
				runtime[ch].video.supported |= VIDEO_SETUP_BITRATE;
				runtime[ch].video.onthefly |= VIDEO_SETUP_BITRATE;
			}
		}
	}
	*/

	for (i = 0; i < onvif_modeldb_cnt; i++)
	{
		if (strncmp(ipcam_onvif_model_db[i].name, runtime[ch].sys.model, strlen(ipcam_onvif_model_db[i].name)) == 0)
		{
			break;
		}
	}

	if (i >= onvif_modeldb_cnt)
	{
		if (strcmp(runtime[ch].sys.vendor, "MESSOA") == 0)
		{
			i = get_the_model_id("ANNEXXUS");
		}
		else
		{
			IPCAM_DBG(MAJOR, "CH(%d) model(%s) Not Found\n", ch, runtime[ch].sys.model);
			if (runtime[ch].sys.http_port == 0)
			{
				runtime[ch].sys.http_port = 80;
			}
			runtime[ch].sys.model_code = NF_IPCAM_MODEL_ONVIF;
			//memcpy(&runtime[ch].video, &model_video_profiles[0],  sizeof(video_t));
			/*if (runtime[ch].onvif.width != 0 && runtime[ch].onvif.height != 0)
			{
				_set_resolution(ch, runtime[ch].onvif.width, runtime[ch].onvif.height);
			}*/

			if(strcmp(runtime[ch].sys.vendor, "Grundig") == 0 || strcmp(runtime[ch].sys.vendor, "GRUNDIG") == 0)
			{
				memcpy(&runtime[ch].funcs, &model_funcs[10], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
				//runtime[ch].funcs[NF_IPCAM_TYPE_SET_ACODEC] = &grundig_set_audio;
				//runtime[ch].sys.model_code = NF_IPCAM_MODEL_ONVIF_GRUNDIG;
				memcpy(&runtime[ch].motion, &model_motion_profiles[3], sizeof(motion_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &grundig_set_motion_area;
				runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
				runtime[ch].recv_handler = model_recv_handlers[3];
			}
			else if(strcmp(runtime[ch].sys.vendor, "AXIS") == 0)
			{
				IPCAM_DBG(MINOR, "CH(%d) AXIS\n", ch);
				memcpy(&runtime[ch].motion, &model_motion_profiles[7], sizeof(motion_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &nf_axis_set_motion;
				runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_IMAGE_ONVIF] = &nf_axis_set_image;
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_MIRROR] = &nf_axis_set_mirror;	
			}
			else if(strcmp(runtime[ch].sys.vendor, "H264") == 0)
			{
				IPCAM_DBG(MINOR, "CH(%d) Xiongmai\n", ch);
				memcpy(&runtime[ch].motion, &model_motion_profiles[10], sizeof(motion_t));
				runtime[ch].funcs[NF_IPCAM_TYPE_SET_MOTION] = &xiongmai_motion_set;
				runtime[ch].func |= NF_IPCAM_FUNC_MOTION;
				runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM0] = &xiongmai_alarm_server_set;
				runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM1] = &xiongmai_osd_off;
				runtime[ch].funcs[NF_IPCAM_TYPE_CUSTOM2] = &xiongmai_prevent_periodical_reboot;
				runtime[ch].func |= NF_IPCAM_FUNC_AUDIO_TX;
			}

			if(nf_ipcam_is_vendor_orion() || nf_ipcam_is_vendor_g4s())
			{
				if(strcasecmp(runtime[ch].sys.vendor, "Orion") == 0 || strcasecmp(runtime[ch].sys.vendor, "G4S") == 0)
				{
					runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[4], sizeof(pmask_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&huviron_set_privacy_mask;
				}
				else if(strcasecmp(runtime[ch].sys.vendor, "HDPRO") == 0)
				{
					runtime[ch].func |= NF_IPCAM_FUNC_PRIVACY_MASK;
					memcpy(&runtime[ch].privacymask, &model_privacy_mask_profiles[5], sizeof(pmask_t));
					runtime[ch].funcs[NF_IPCAM_TYPE_SET_PMASK] = (gpointer)&nf_hdpro_set_privacy_mask;
				}
			}

			int rtn = nf_onvif_get_video_capability(ch);
			if(runtime[ch].onvif.onvif_service & __OFM(NF_ONVIF_SERVICE_MEDIA2))
			{
				nf_onvif_get_video_capability_media2(ch);
			}

			if(rtn == -2)
			{
				if (nf_get_running_mode())
				{
					runtime[ch].state = OPENMODE_STATE_CONFIG_FAIL;
				}
				else
				{
					nf_pnd_queue_push(ch, IPCAM_EVENT_CONFIG_FAIL, __LINE__, __FILE__);
				}
				IPCAM_DBG(WARN, "Cannot find Compatible ONVIF Resolution!!(CH:%d)\n", ch);
				return IPX_SEARCH_CONNECTION_FAILED;
			}

			if(!runtime[ch].encoder.res_support[0]) runtime[ch].encoder.res_support[0] |= runtime[ch].video.resolution.resolution[0];
			if(!runtime[ch].encoder.res_support[1]) runtime[ch].encoder.res_support[1] |= runtime[ch].video.resolution.resolution[1];

#if defined(_IPX_1648P)||defined(_IPX_0824VE)||defined(_IPX_0412VE)||defined(_IPX_0824ECO)||defined(_IPX_0412ECO) \
		|| defined(_IPX_1648VE3) || defined(_IPX_1648P3) || defined(_IPX_1648P3ECO)
			if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
			{
				runtime[ch].encoder.max_bitrate[0] = 4000;
			}
#else
			if(runtime[ch].encoder.max_bitrate[0] > 8000)
			{
				runtime[ch].encoder.max_bitrate[0] = 8000;
			}
			else if(runtime[ch].encoder.max_bitrate[0] <= 0)
			{
				runtime[ch].encoder.max_bitrate[0] = 8000;
			}
#endif

			if(runtime[ch].encoder.max_bitrate[1] > 1500 || runtime[ch].encoder.max_bitrate[1] <= 0)
				runtime[ch].encoder.max_bitrate[1] = 1500;

			if(runtime[ch].encoder.min_bitrate[0] < 1000)
				runtime[ch].encoder.min_bitrate[0] = 1000;

			if(runtime[ch].encoder.min_bitrate[1] < 256)
				runtime[ch].encoder.min_bitrate[1] = 256;
/*
			if(!nf_ipcam_is_vendor("CBC")) {
				if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
						&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
				{
					runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
					runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
				}

				if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_VBR)
						&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_VBR))
				{
					runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;	
					runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;	
				}
			}
*/
			//min bitrate modify
			runtime[ch].encoder.min_bitrate[0] = 1000;
			runtime[ch].encoder.min_bitrate[1] = 600;

			if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
			{
				//IPXUHD-1660
				//runtime[ch].encoder.max_bitrate[0] = 8000;
				//runtime[ch].encoder.max_bitrate[1] = 2000;
				runtime[ch].encoder.max_bitrate[0] = 4000;
				runtime[ch].encoder.max_bitrate[1] = 1000;
				runtime[ch].encoder.min_bitrate[0] = 1000;
				runtime[ch].encoder.min_bitrate[1] = 600;

				if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
						&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
				{
					runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
					runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
				}

				if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
						&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
				{
					runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
					runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
				}
			}

			return IPX_SEARCH_FOUND_NOT_SUPPORTED;
		}
	}

	found = (profile*) &ipcam_onvif_model_db[i];

	runtime[ch].func = found->func;
	runtime[ch].profile_id = i;

	//strncpy(runtime[ch].username, default_usernames[found->user], 64);
	//strncpy(runtime[ch].password, default_passwords[found->pass], 64);

	runtime[ch].sys.rx_method = NF_IPCAM_RX_METHOD_RTSP_TCP;
	//runtime[ch].sys.rtsp_port[0] = found->rtsp_port[0];
	//runtime[ch].sys.rtsp_port[1] = found->rtsp_port[1];
	//runtime[ch].sys.rtsp_port[2] = found->rtsp_port[2];
	//runtime[ch].sys.http_port = found->http_port;

	runtime[ch].sys.model_code = found->model_code;
	//strncpy(runtime[ch].sys.model, found->name, 64);
	//strncpy(runtime[ch].sys.swver, model.swver, 128);
	//strncpy(runtime[ch].sys.vendor, model_vendor_names[found->vendor], 64);

	memcpy(&runtime[ch].video, &model_video_profiles[found->video],  sizeof(video_t));
	memcpy(&runtime[ch].audio, &model_audio_profiles[found->audio],  sizeof(audio_t));
	memcpy(&runtime[ch].image, &model_image_profiles[found->image],  sizeof(image_t));
	memcpy(&runtime[ch].ptz,   &model_ptz_profiles[found->ptz],      sizeof(ptz_t));
	memcpy(&runtime[ch].alarm, &model_alarm_profiles[found->alarm],  sizeof(alarm_t));
	memcpy(&runtime[ch].motion,&model_motion_profiles[found->motion],sizeof(motion_t));

	get_ipstr(runtime[ch].sys.ipaddr, ip_buf);
	/*for (i = 0; i < runtime[ch].video.stream_cnt; i++)
	{
		snprintf(runtime[ch].sys.rtsp_url[i], 256, model_rtsp_addrs[found->rtsp[i]], ip_buf);
	}*/

	memcpy(&runtime[ch].funcs, &model_funcs[found->funcs], sizeof(gpointer)*NF_IPCAM_TYPE_MAX);
	runtime[ch].recv_handler = model_recv_handlers[found->recv_handler];

	int rtn = nf_onvif_get_video_capability(ch);
	if(runtime[ch].onvif.onvif_service & __OFM(NF_ONVIF_SERVICE_MEDIA2))
	{
		nf_onvif_get_video_capability_media2(ch);
	}

	if(rtn == -2)
	{
		if (nf_get_running_mode())
		{
			runtime[ch].state = OPENMODE_STATE_CONFIG_FAIL;
		}
		else
		{
			nf_pnd_queue_push(ch, IPCAM_EVENT_CONFIG_FAIL, __LINE__, __FILE__);
		}
		IPCAM_DBG(WARN, "Cannot find Compatible ONVIF Resolution!!(CH:%d)\n", ch);
		return IPX_SEARCH_CONNECTION_FAILED;
	}

	runtime[ch].encoder.res_support[0] |= runtime[ch].video.resolution.resolution[0];
	runtime[ch].encoder.res_support[1] |= runtime[ch].video.resolution.resolution[1];

#if defined(_IPX_1648P)||defined(_IPX_0824VE)||defined(_IPX_0412VE)||defined(_IPX_0824ECO)||defined(_IPX_0412ECO) \
		|| defined(_IPX_1648VE3) || defined(_IPX_1648P3) || defined(_IPX_1648P3ECO)
		
	if(runtime[ch].encoder.max_bitrate[0] > 4000 || runtime[ch].encoder.max_bitrate[0] <= 0)
	{
		runtime[ch].encoder.max_bitrate[0] = 4000;
	}
#else
	if(runtime[ch].encoder.max_bitrate[0] > 8000)
	{
		runtime[ch].encoder.max_bitrate[0] = 8000;
	}
	else if(runtime[ch].encoder.max_bitrate[0] <= 0)
	{
		runtime[ch].encoder.max_bitrate[0] = 8000;
	}
#endif

	if(runtime[ch].encoder.max_bitrate[1] > 1500 || runtime[ch].encoder.max_bitrate[1] <= 0)
		runtime[ch].encoder.max_bitrate[1] = 1500;

	if(runtime[ch].encoder.min_bitrate[0] < 1000)
		runtime[ch].encoder.min_bitrate[0] = 1000;

	if(runtime[ch].encoder.min_bitrate[1] < 256)
		runtime[ch].encoder.min_bitrate[1] = 256;
	/*
	if(!nf_ipcam_is_vendor("CBC")) {
		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
				&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_VBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_VBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;	
		}
	}
	*/

	//min bitrate modify
	runtime[ch].encoder.min_bitrate[0] = 1000;
	runtime[ch].encoder.min_bitrate[1] = 600;

#if defined(_IPX_32P4E)  || defined(_IPX_32M4E) || defined(_IPX_32P5)
	runtime[ch].encoder.max_bitrate[0] = 4000;
	runtime[ch].encoder.max_bitrate[1] = 1000;

	runtime[ch].encoder.min_bitrate[0] = 1500;
	runtime[ch].encoder.min_bitrate[1] = 600;

	if(runtime[ch].encoder.bitctrl[0] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_VBR;
	if(runtime[ch].encoder.bitctrl[1] & NF_IPCAM_BITRATE_CONTROL_VBR)
		runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_VBR;
#endif
	
	if(nf_ipcam_is_vendor_videcon())	//Videcon vendor Max BPS 4M (SALESQNA-1608), SWIPXVETHR-1712
	{
		//IPXUHD-1660
		//runtime[ch].encoder.max_bitrate[0] = 8000;
		//runtime[ch].encoder.max_bitrate[1] = 2000;
		runtime[ch].encoder.max_bitrate[0] = 4000; // 32ch
		runtime[ch].encoder.max_bitrate[1] = 1000;
		runtime[ch].encoder.min_bitrate[0] = 1000;
		runtime[ch].encoder.min_bitrate[1] = 600;

		if(((runtime[ch].encoder.vcodec[0]) & NF_IPCAM_VCODEC_H265) 
				&& ((runtime[ch].encoder.vcodec[1]) & NF_IPCAM_VCODEC_H265))
		{
			runtime[ch].video.vcodec[0] = NF_IPCAM_VCODEC_H265;
			runtime[ch].video.vcodec[1] = NF_IPCAM_VCODEC_H265;
		}

		if(((runtime[ch].encoder.bitctrl[0]) & NF_IPCAM_BITRATE_CONTROL_CBR)
				&& ((runtime[ch].encoder.bitctrl[1]) & NF_IPCAM_BITRATE_CONTROL_CBR))
		{
			runtime[ch].video.bitctrl[0] = NF_IPCAM_BITRATE_CONTROL_CBR;	
			runtime[ch].video.bitctrl[1] = NF_IPCAM_BITRATE_CONTROL_CBR;	
		}
	}

	if(nf_ipcam_is_vendor_dayou())
	{
		if(strcmp(runtime[ch].sys.model, "IPFX-B40V-IRW2")==0)
		{
			runtime[ch].encoder.vcodec[0] &= ~NF_IPCAM_VCODEC_H265;
			runtime[ch].encoder.vcodec[1] &= ~NF_IPCAM_VCODEC_H265;
		}
	}

	_modify_2nd_stream_supported_res(ch);
    nf_api_ai_config_update(ch);

	return IPX_SEARCH_FOUND_AND_SET;
}


static void get_ipstr(unsigned int ip, char* outbuf)
{
	snprintf(outbuf, 16, "%d.%d.%d.%d", (ip&0xff), ((ip&0xff00)>>8), 
			((ip&0xff0000)>>16), ((ip&0xff000000)>>24));
}
static int get_the_model_id(const char* model_name)
{
	int i = 0;
	for (i = 0; i < onvif_modeldb_cnt; i++)
	{
		if (strncmp(ipcam_onvif_model_db[i].name, model_name, strlen(model_name)) == 0)
		{
			break;
		}
	}

	return i;
}


