/**
 * @brief Image탭의 option struct를 조회한다.
 * @param func Image탭의 기능 enum값. @see _NF_IPCAM_IMAGE_ONVIF
 * @param value func의 옵션 중 하나.
 * @return 해당하는 option struct.
 */
extern NFIPCamOption_onvif* get_cam_model_option_image(uint64_t func, unsigned int value)
{
	NFIPCamOption_onvif* rtn = NULL;
	int i = 0;

	switch(func)
	{
		case NF_IPCAM_IMAGE_ONVIF_FOCUS_MODE:		// 4
			for(i = 0; i < NF_IPCAM_FOCUS_MODE_ONVIF_NR; i++)
			{
				if(value == _nf_focus_options_onvif[i].value)
				{
					rtn = &_nf_focus_options_onvif[i];
					return rtn;
				}
			}

			break;
		case NF_IPCAM_EXPOSURE_ONVIF_IRCUT:			// 19
			for(i = 0; i < NF_IPCAM_IRCUT_MODE_ONVIF_NR; i++)
			{
				if(value == _nf_ircut_options_onvif[i].value)
				{
					rtn = &_nf_ircut_options_onvif[i];
					return rtn;
				}
			}

			break;
		case NF_IPCAM_IMAGE_ONVIF_WB_MODE:			// 14
			for(i = 0; i < NF_IPCAM_WB_MODE_ONVIF_NR; i++)
			{
				if(value == _nf_wb_options_onvif[i].value)
				{
					rtn = &_nf_wb_options_onvif[i];
					return rtn;
				}
			}

			break;
		case NF_IPCAM_IMAGE_ONVIF_WB_PRESET:		// 24
			for(i = 0; i < NF_IPCAM_IMAGE_MWB_MODE_NR; i++)
			{
				if(value == _nf_wb_prs_options_onvif[i].value)
				{
					rtn = &_nf_wb_prs_options_onvif[i];
					return rtn;
				}
			}

			break;

		case NF_IPCAM_EXPOSURE_ONVIF_DNN_TOGGLE:		// 26
			for(i = 0; i < NF_IPCAM_IMAGE_TGTIME_NR; i++)
			{
				if(value == _nf_dnn_toggle_options_onvif[i].value)
				{
					rtn = &_nf_dnn_toggle_options_onvif[i];
					return rtn;
				}
			}

			break;
		case NF_IPCAM_IMAGE_ONVIF_ROTATION:			// 20
			for(i = 0; i < NF_IPCAM_MIRROR_NR; i++)
			{
				if(value == _nf_mirror_options_onvif[i].value)
				{
					rtn = &_nf_mirror_options_onvif[i];
					return rtn;
				}
			}

			break;
		case NF_IPCAM_IMAGE_ONVIF_FOCUS_LIMIT:
			for(i = 0; i < NF_IPCAM_IMAGE_FOCUS_LIMIT_NR; i++)
			{
				if(value == _nf_focus_limit_options_onvif[i].value)
				{
					rtn = &_nf_focus_limit_options_onvif[i];
					return rtn;
				}
			}
			break;

		case NF_IPCAM_IMAGE_ONVIF_STABILIZER:
			for(i = 0; i < NF_IPCAM_IMAGE_STABILIZER_NR; i++)
			{
				if(value == _nf_stabilizer_options_onvif[i].value)
				{
					rtn = &_nf_stabilizer_options_onvif[i];
					return rtn;
				}
			}
			break;
		case NF_IPCAM_IMAGE_ONVIF_IR_CORRECTION:
			for(i = 0; i < NF_IPCAM_IMAGE_IR_CORRECTION_NR; i++)
			{
				if(value == _nf_ir_correction_options_onvif[i].value)
				{
					rtn = &_nf_ir_correction_options_onvif[i];
					return rtn;
				}
			}
			break;


		default:
			IPCAM_DBG(ERROR, "model option get failed(%llu, %x)\n", func, value);
			break;

	}

	return NULL;
}

